window.__LIBQ=window.__LIBQ||{};window.__LIBQ["tien-nghich"]=window.__LIBQ["tien-nghich"]||{};window.__LIBQ["tien-nghich"]["q08"]=window.__LIBQ["tien-nghich"]["q08"]||{};window.__LIBQ["tien-nghich"]["q08"]["techniques"]={"updatedAt":"2026-07-09","count":159,"techniques":[{"id":"than-thuc-dung-nhap-muoi-ba-huyet-cau","name":"Thần thức dung nhập mười ba huyết cầu","cn":"","loai":"than-thong","loaiLabel":"Thần thức phối hợp pháp bảo","phamCap":"Không rõ","hePhai":"La Thiên","soHuu":["Liệt Vân Tử"],"blurb":"Cách Liệt Vân Tử dung nhập thần thức vào mười ba huyết cầu La Phù để mở rộng cảm ứng. Nhờ đó lão trấn giữ vùng đình chiến và khó bỏ sót động tĩnh trên phạm vi rộng.","detail":"Tại tu chân tinh gần chiến trường cũ, Liệt Vân Tử dùng thần thức dung nhập vào mười ba huyết cầu La Phù. Phối hợp này khiến phạm vi tâm thần của lão tăng mạnh, phục vụ việc đề phòng Liên Minh Tu Chân tiếp tục tấn công tiền tuyến.","nguon":["@c0888"]},{"id":"uy-ap-muoi-ba-con-mat-do","name":"Uy áp mười ba con mắt đỏ","cn":"","loai":"than-thong","loaiLabel":"Uy áp","phamCap":"Không rõ","hePhai":"La Thiên","soHuu":["Liệt Vân Tử"],"blurb":"Uy áp hình thành khi mười ba huyết cầu hiện ra mười ba con mắt đỏ. Ánh mắt từ các huyết cầu ngưng tụ thành sức ép khổng lồ trên bầu trời.","detail":"Mười ba huyết cầu La Phù quanh Liệt Vân Tử hiện ra mười ba con mắt đỏ, ánh mắt hội tụ tạo cảm giác như một loại thần thông uy áp. Khí thế ấy gắn với năng lực phòng thủ và trấn nhiếp của La Phù tại tiền tuyến.","nguon":["@c0888"]},{"id":"mot-tieng-on-ao-cua-vuong-lam","name":"Một tiếng “Ồn ào!” của Vương Lâm","cn":"","loai":"than-thong","loaiLabel":"Uy áp ý chí","phamCap":"Không rõ","hePhai":"Cổ Thần","soHuu":["Vương Lâm"],"blurb":"Uy thế bộc phát qua ánh mắt và tiếng quát của Vương Lâm. Chỉ một tiếng đã khiến Hứa Đình tâm thần chấn động, phun máu và hoảng sợ.","detail":"Khi Hứa Đình bộc lộ sát khí, Vương Lâm dùng ánh mắt cùng tiếng quát “Ồn ào!” đánh thẳng vào tâm thần đối phương. Hiệu quả thể hiện khí tức áp đảo sau biến đổi thân thể Cổ Thần, đủ khiến Hứa Đình mất thế phản kháng và khiến Liệt Vân Tử thay đổi cách nhìn.","nguon":["@c0888"]},{"id":"chien-tu-luc-thiep","name":"Chiến Tự Lục Thiếp","cn":"","loai":"cong-phap","loaiLabel":"Truyền thừa","phamCap":"không rõ","hePhai":"Chiến","soHuu":["Lão già mặc y phục màu trắng"],"blurb":"Truyền thừa gồm sáu bức Chiến Tự Thiếp do lão giả áo trắng lưu lại. Người đời sau nếu thu hoạch toàn bộ sẽ trở thành truyền nhân của ông.","detail":"Trong ý cảnh Đệ Nhị Phúc, lão giả áo trắng nói mình cả đời không có truyền nhân nên đặt toàn bộ vào chữ Chiến và lưu lại sáu bức Chiến Tự Thiếp. Truyền thừa này gắn với việc thu đủ sáu thiếp.","nguon":["@c0889"]},{"id":"de-nhat-loi-chien-thiep","name":"Đệ Nhất Lôi—Chiến Thiếp","cn":"","loai":"cong-phap","loaiLabel":"Thiếp truyền thừa","phamCap":"không rõ","hePhai":"Chiến","soHuu":["Hứa Đình"],"blurb":"Thiếp truyền thừa liên quan đến bản nguyên mà Hứa Đình từng thu được. Khi Hứa Đình bị thú linh thôn phệ trong Đệ Nhị Phúc, luồng bản nguyên này bị hút mất.","detail":"Đệ Nhất Lôi—Chiến Thiếp được nhắc như nguồn bản nguyên Hứa Đình từng thu hoạch năm xưa. Việc bản nguyên ấy bị Chiến Tự Thiếp Đệ Nhị Phúc hút đi cho thấy các thiếp có liên hệ và rủi ro mất thành quả truyền thừa.","nguon":["@c0889"]},{"id":"khong-chi","name":"Không Chi","cn":"","loai":"khac","loaiLabel":"Cảnh giới","phamCap":"không rõ","hePhai":"không rõ","soHuu":["Lão già mặc y phục màu trắng"],"blurb":"Cảnh giới mà lão giả áo trắng tự xưng đạt được ba vạn năm trước. Đây là nền tảng khiến truyền thừa Chiến Tự Lục Thiếp trở nên trọng yếu.","detail":"Trong ý cảnh của Chiến Tự Thiếp Đệ Nhị Phúc, lão giả áo trắng nói ba vạn năm trước ông đã tự tu luyện tới cảnh giới Không Chi. Chương chưa giải thích đầy đủ hệ thống của cảnh giới này.","nguon":["@c0889"]},{"id":"u-minh-dan-lo","name":"U Minh Dẫn Lộ","cn":"","loai":"than-thong","loaiLabel":"Tiên thuật dẫn đường","phamCap":"Không rõ","hePhai":"Tiên Thuật U Minh","soHuu":["Thanh Thủy"],"blurb":"U Minh Dẫn Lộ là tiên thuật Thanh Thủy dùng để mở đường vào Sát Vực Giới. Pháp thuật gom ký ức, tình cảm và ý niệm của hơn trăm tu sĩ Sát Vực Giới thành một hắc động dẫn lối.","detail":"Thanh Thủy dùng hơn trăm đầu lâu và tàn hồn tu sĩ Sát Vực Giới làm môi giới, nghiền thành sương máu rồi ngưng tụ toàn bộ ý niệm liên quan tới Sát Vực Giới. Kết quả là một con đường màu đen hình thành, dẫn thẳng vào Sát Vực Giới để Thanh Thủy và Vương Lâm xâm nhập.","nguon":["@c0890"]},{"id":"tien-thuat-u-minh","name":"Tiên Thuật U Minh","cn":"","loai":"than-thong","loaiLabel":"Tiên thuật","phamCap":"Không rõ","hePhai":"U Minh","soHuu":["Thanh Thủy"],"blurb":"Tiên Thuật U Minh là pháp thuật Thanh Thủy khởi phát trước khi tạo U Minh Dẫn Lộ. Nó khiến hơn trăm đầu người nổ tung thành sương máu và tàn hồn.","detail":"Khi Thanh Thủy thi triển tiên thuật này, hơn trăm đầu lâu tu sĩ Sát Vực Giới bị nghiền nát, tàn hồn tan ra, tạo nền để gom ký ức và ý niệm về Sát Vực Giới thành đường dẫn.","nguon":["@c0890"]},{"id":"phap-thuat-tan-anh","name":"Pháp thuật Tàn Anh","cn":"","loai":"bi-thuat","loaiLabel":"Pháp thuật cứu mạng","phamCap":"Không rõ","hePhai":"Không rõ","soHuu":[],"blurb":"Pháp thuật Tàn Anh được Liệt Vân Tử nhắc như một loại pháp thuật có thể cứu người sau biến cố nguy hiểm. Chiến Gia không có pháp thuật này.","detail":"Khi bàn chuyện để Vương Lâm xem Đệ Tam Phúc Chiến Tự Thiếp, Liệt Vân Tử nói Chiến Gia không có pháp thuật Tàn Anh để cứu Vương Lâm sống lại nếu xảy ra bất trắc, nhưng có một công pháp bảo mệnh khác có thể truyền về sau.","nguon":["@c0890"]},{"id":"thuat-an-giau","name":"Thuật ẩn giấu","cn":"","loai":"than-thong","loaiLabel":"Thần thông ẩn nấp","phamCap":"không rõ","hePhai":"Sát Vực Giới","soHuu":["Tu sĩ Sát Vực Giới"],"blurb":"Thủ đoạn ẩn nấp nổi danh của người Sát Vực Giới. Họ thường một đòn không trúng liền lui xa và biến mất tung tích.","detail":"Sát Vực Giới nổi tiếng am hiểu thuật ẩn giấu, khiến cả tu sĩ đại thần thông cũng đau đầu khi đối phó. Phong cách hành sự của họ là ám sát, lui xa và che giấu khí tức sau khi ra tay không thành.","nguon":["@c0891"]},{"id":"bay-tran","name":"Bày trận","cn":"","loai":"khac","loaiLabel":"Trận pháp hiệu lệnh","phamCap":"không rõ","hePhai":"Sát Vực Giới","soHuu":["Tu sĩ Khuy Niết trung kỳ Sát Vực Giới"],"blurb":"Hiệu lệnh trận pháp của tu sĩ Sát Vực Giới khi đối phó Vương Lâm. Lệnh vừa phát ra thì Vương Lâm đã áp sát khiến trận thế khó kịp thành hình.","detail":"Tu sĩ Khuy Niết trung kỳ Sát Vực Giới hét lệnh bày trận trong lúc đối mặt Vương Lâm. Đây là phản ứng tổ chức lực lượng của phe Sát Vực Giới, nhưng bị tốc độ và áp lực của Vương Lâm phá vỡ trước khi tạo được cục diện hữu hiệu.","nguon":["@c0891"]},{"id":"ban-tay-co-than","name":"Bàn tay Cổ Thần","cn":"","loai":"than-thong","loaiLabel":"Thần thông thể thuật Cổ Thần","phamCap":"Cổ Thần","hePhai":"Cổ Thần","soHuu":["Vương Lâm"],"blurb":"Thủ đoạn dùng thân thể Cổ Thần của Vương Lâm hóa tay phải thành bàn tay khổng lồ. Trong trận Sát Vực Giới, nó chụp phi kiếm bản mệnh của tu sĩ Khuy Niết trung kỳ và cắt đứt liên hệ tâm thần.","detail":"Vương Lâm vận dụng sức mạnh thân thể Cổ Thần, vung tay phải hóa thành bàn tay Cổ Thần để cưỡng đoạt pháp bảo của đối phương. Đòn này khiến tu sĩ Khuy Niết trung kỳ nhớ tới cái chết của Vu Phi, đồng thời thể hiện sức áp đảo của thân thể Ngũ Tinh Vương Tộc Cổ Thần.","nguon":["@c0891"]},{"id":"dong-bang-thien-dia","name":"Đóng Băng Thiên Địa","cn":"","loai":"than-thong","loaiLabel":"Thần thông băng hệ","phamCap":"không rõ","hePhai":"Thanh Thủy","soHuu":["Thanh Thủy"],"blurb":"Thần thông băng hệ do Thanh Thủy thi triển tại Sát Vực Giới. Hàn khí khiến mưa hóa tuyết, lam quang bao phủ đất trời và phong tỏa đường thoát của phó giới chủ.","detail":"Thanh Thủy vận chuyển tiên nguyên thi triển Đóng Băng Thiên Địa, tạo hàn khí lan khắp Sát Vực Giới. Lam quang từ thần thông này bao phủ không gian, khóa khe nứt hư vô trong tháp trung tâm và khiến phó giới chủ không thể hoàn tất thoát thân.","nguon":["@c0891"]},{"id":"tam-hac-long","name":"Tám Hắc Long","cn":"","loai":"than-thong","loaiLabel":"Thần thông công kích","phamCap":"không rõ","hePhai":"Thanh Thủy","soHuu":["Thanh Thủy"],"blurb":"Thần thông công kích Thanh Thủy dùng khi đối đầu phó giới chủ Sát Vực Giới. Tám Hắc Long được gọi ra giữa đất trời và lao về phía lão già hắc y.","detail":"Thanh Thủy điểm chỉ gọi ra tám Hắc Long gầm rống giữa đất trời, dùng chúng kiềm chế một thân của phó giới chủ Sát Vực Giới. Đòn này phối hợp với Đóng Băng Thiên Địa để phá thế phân thân bỏ chạy của đối phương.","nguon":["@c0891"]},{"id":"co-than-tinh-diem","name":"Cổ Thần Tinh Điểm","cn":"","loai":"than-thong","loaiLabel":"Cổ Thần năng lực","phamCap":"Không rõ","hePhai":"Cổ Thần","soHuu":["Vương Lâm"],"blurb":"Tinh điểm Cổ Thần trên mi tâm Vương Lâm xoay tròn, giúp hắn ngưng tinh quang hóa ra Diệt Thần Mâu hư ảo.","detail":"Trong trận tại Sát Vực Giới, Vương Lâm vận Cổ Thần Tinh Điểm để tạo Diệt Thần Mâu dạng hư ảo chống lại tử quang chứa Cực Cảnh, qua đó xác nhận pháp khí Vương tộc Cổ Thần có thể khắc chế Cực Cảnh ở mức nhất định.","nguon":["@c0892"]},{"id":"van-quan-chi-thuy","name":"Vạn Quân Chi Thủy","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Sát Vực Giới","soHuu":["Tu sĩ Khuy Niết trung kỳ dùng Vạn Quân Chi Thủy"],"blurb":"Thần thông dùng nguyên đan đen hóa thành hắc thủy tràn nửa không trung.","detail":"Một tu sĩ Khuy Niết trung kỳ của Sát Vực Giới phóng nguyên đan màu đen từ thiên linh, hóa thành làn hắc thủy như biển quét ngang về phía Vương Lâm trong vòng vây phi kiếm.","nguon":["@c0892"]},{"id":"hoa-huyet-tien-vong","name":"Hóa Huyết Tiên Võng","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Sát Vực Giới","soHuu":["Tu sĩ Khuy Niết trung kỳ dùng Hóa Huyết Tiên Võng"],"blurb":"Thần thông huyết pháp biến huyết quang và tơ máu thành võng máu trói địch.","detail":"Một tu sĩ Khuy Niết trung kỳ của Sát Vực Giới thi triển Hóa Huyết Tiên Võng, khiến toàn thân hiện huyết quang và tơ máu, hóa thành võng máu điên cuồng quấn về phía Vương Lâm.","nguon":["@c0892"]},{"id":"loi-dinh-khuat-phuc-duoi-loi-rong","name":"Lôi đình khuất phục dưới lôi rống","cn":"","loai":"than-thong","loaiLabel":"Lôi đạo thần thông","phamCap":"Không rõ","hePhai":"Thái Cổ Lôi Long","soHuu":["Vương Lâm","Thái Cổ Lôi Long"],"blurb":"Vương Lâm hiện nguyên thần Thái Cổ Lôi Long, dùng tiếng rống dẫn lôi đình khắp Sát Vực Giới tụ lại.","detail":"Khi tàn hồn trong tinh quang phản phệ, Vương Lâm gọi nguyên thần Thái Cổ Lôi Long, dẫn lôi đình bốn phương tám hướng bao phủ thiên địa Sát Vực Giới, dùng lôi lực áp đảo tinh quang và khiến tàn hồn thần phục.","nguon":["@c0892"]},{"id":"ho-phong","name":"Hô Phong","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"không rõ","hePhai":"không rõ","soHuu":["Vương Lâm"],"blurb":"Thần thông được Vương Lâm thi triển để hóa hắc phong thành ba hắc long. Trong chương 893, nó dùng để chống lại đòn tập kích của Huyễn Hư Tử.","detail":"Khi Huyễn Hư Tử điều động bốn nữ nhân từ Bạch Ngọc Hồ Lô và hóa khói hồng áp sát, Vương Lâm thi triển Hô Phong khiến hắc phong gào thét trong thiên địa, hóa thành ba hắc long. Một hắc long bị bóng hư ảo quấn lấy, hai hắc long còn lại lao vào Huyễn Hư Tử nhưng xuyên qua thân thể hư ảo của hắn.","nguon":["@c0893"]},{"id":"hong-trach-hoang-sa","name":"Hồng Trạch Hoang Sa","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"không rõ","hePhai":"Sát Vực giới","soHuu":["Huyễn Hư Tử"],"blurb":"Thần thông của Huyễn Hư Tử, dùng nguyên lực thiên địa ngưng thành cát đen chứa trận pháp và hồng trạch. Nhờ quy tắc ảo, nó biến thành cánh tay khổng lồ đối oanh Cổ Thần quyền.","detail":"Huyễn Hư Tử thi triển Hồng Trạch Hoang Sa bằng cách lấy nguyên lực thiên địa hóa thành cát đen, trong cát có trận pháp và hồng trạch. Khi kết hợp quy tắc ảo, ảo pháp này hóa thành cánh tay khổng lồ, giao phong trực diện với Cổ Thần lực của Vương Lâm.","nguon":["@c0893"]},{"id":"quy-tac-ao","name":"Quy tắc ảo","cn":"","loai":"khac","loaiLabel":"Quy tắc","phamCap":"Tịnh Niết","hePhai":"Huyễn Hư Tử","soHuu":["Huyễn Hư Tử"],"blurb":"Quy tắc do Huyễn Hư Tử ngộ ra. Nó khiến Hồng Trạch ảo pháp có thể hóa thành thực thể để đối kháng công kích của Vương Lâm.","detail":"Huyễn Hư Tử tự nói quy tắc của mình là quy tắc ảo. Trong giao phong với Vương Lâm, hắn dùng quy tắc này để biến Hồng Trạch Hoang Sa thành công kích hữu hình, mô phỏng cánh tay khổng lồ đối oanh với Cổ Thần quyền.","nguon":["@c0893"]},{"id":"co-than-luc-co-than-quyen","name":"Cổ Thần lực / Cổ Thần quyền","cn":"","loai":"luyen-the","loaiLabel":"Thần thông thể phách","phamCap":"Cổ Thần","hePhai":"Cổ Thần","soHuu":["Vương Lâm"],"blurb":"Sức mạnh Cổ Thần được Vương Lâm vận vào cánh tay để đánh ra một quyền khổng lồ. Trong chương 893, nó được dùng đối kháng nguyên lực thiên địa của tu sĩ Tịnh Niết.","detail":"Vương Lâm vận chuyển tinh điểm Cổ Thần dưới mi tâm tam nhãn vào cánh tay, khiến cánh tay hóa thành quyền ảnh khổng lồ. Đòn này va chạm với cánh tay cát do Hồng Trạch Hoang Sa và quy tắc ảo tạo ra, gây dư ba mạnh tới mức cuốn chết tu sĩ xung quanh.","nguon":["@c0893"]},{"id":"chin-muoi-chin-kiem-tran","name":"Chín mươi chín kiếm trận","cn":"","loai":"kiem-quyet","loaiLabel":"Kiếm trận","phamCap":"Không rõ","hePhai":"Sát Vực Giới","soHuu":["Lăng Vân Tử"],"blurb":"Kiếm trận mà giới chủ Sát Vực Giới nghĩ tới trong lúc đối mặt Thanh Thủy. Muốn thi triển cần đủ Tịnh Niết tu sĩ trợ giúp.","detail":"Trong biến cố Sát Vực Giới, Lăng Vân Tử cho rằng nếu phần lớn Tịnh Niết tu sĩ không tới Tổng bộ Liên Minh thì hắn có thể dùng chín mươi chín kiếm trận để đối kháng. Dù vậy, hắn vẫn sợ kiếm trận khó chống nổi thần thông của Thanh Thủy.","nguon":["@c0894"]},{"id":"thuat-tien-ve-cua-tien-de-thanh-lam","name":"Thuật tiên vệ của tiên đế Thanh Lâm","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"khong-ro","hePhai":"Thanh Lâm","soHuu":["Thanh Lâm","Vương Lâm","Tháp Sơn"],"blurb":"Thuật luyện và khống chế tiên vệ liên quan tới Tháp Sơn. Thuật này hòa tan nguyên thần trong cơ thể tiên vệ nhưng vẫn để lại thần trí, khiến Tháp Sơn khác với khôi lỗi thường.","detail":"Trong chương 895, Vương Lâm dựa vào phong ấn tiên vệ để cảm ứng vị trí Tháp Sơn. Tháp Sơn tuy là tiên vệ nhưng vẫn có thần trí, sau khi mất liên hệ với Vương Lâm đã mờ mịt dung nhập vào cự thạch để tĩnh tọa, rồi hiện thân cung kính khi chủ nhân tìm tới.","nguon":["@c0895"]},{"id":"an-ky-cua-dai-dau","name":"Ấn ký của Đại Đầu","cn":"","loai":"bi-thuat","loaiLabel":"Ấn ký liên hệ","phamCap":"khong-ro","hePhai":"Vương Lâm","soHuu":["Vương Lâm","Đại Đầu"],"blurb":"Ấn ký giúp Vương Lâm cảm ứng tình trạng và vị trí của Đại Đầu. Khi ấn ký trở nên rất yếu, Vương Lâm nhận ra Đại Đầu đang nguy cấp.","detail":"Sau khi thu hồi Tháp Sơn, Vương Lâm cảm nhận ấn ký của Đại Đầu yếu đến mức như sắp tiêu tan. Dấu hiệu này khiến hắn lập tức chuyển hướng đi tìm Đại Đầu và Lôi Cát, dẫn tới việc kịp thời phá đòn công kích của thiếu gia áo lam.","nguon":["@c0895"]},{"id":"thu-an-mau-den","name":"Thủ ấn màu đen","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"khong-ro","hePhai":"khong-ro","soHuu":["Thiếu gia áo lam truy sát Lôi Cát"],"blurb":"Ấn pháp công kích để lại dấu tay đen ở hậu tâm Đại Đầu. Nó khiến huyết nhục hư thối, bốc khói đen và tử khí lan tràn.","detail":"Đại Đầu bị một thủ ấn màu đen đánh vào hậu tâm, vết thương lõm xuống và tỏa mùi tanh tưởi. Thương thế khiến ý thức hắn mơ hồ, ấn ký suy yếu như sắp tiêu tan, đặt hắn vào tình thế sinh tử cho tới khi Vương Lâm xuất hiện.","nguon":["@c0895"]},{"id":"hat-anh-dao-hoa-bo-xuong-kho-mau-luc","name":"Hạt anh đào hóa bộ xương khô màu lục","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"khong-ro","hePhai":"khong-ro","soHuu":["Thiếu gia áo lam truy sát Lôi Cát"],"blurb":"Thuật công kích qua vật dẫn của thiếu gia áo lam. Hạt anh đào bị phun ra hóa cầu vồng rồi thành bộ xương khô màu lục để đánh vào Lôi Cát.","detail":"Trong lúc truy sát, thiếu gia áo lam phun một hạt anh đào khiến nó hóa thành cầu vồng, rồi biến thành bộ xương khô màu lục. Bộ xương định ấn xuống đốt sống lưng thứ tám của Lôi Cát, nhưng bị bàn tay từ hư vô của Vương Lâm bóp nát trước khi thành công.","nguon":["@c0895"]},{"id":"hai-long-thuy-he-than-thong","name":"Hải long thủy hệ thần thông","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"không rõ","hePhai":"thủy hệ","soHuu":["Tôn Cẩu Tử"],"blurb":"Thủy hệ thần thông của Tôn Cẩu Tử, tạo biển nước và ngưng tụ hải long công kích đối thủ.","detail":"Tôn Cẩu Tử bấm quyết tạo biển trăm trượng dưới chân, ngưng tụ nước biển thành hải long lao vào Vương Lâm. Thần thông này bị Vương Lâm phất tay đánh tan trong giao chiến.","nguon":["@c0896"]},{"id":"ngu-quy-am-than-chuyen-luan-khong","name":"Ngũ quỷ âm thần Chuyển Luân không","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"không rõ","hePhai":"Thi Âm Tông","soHuu":["Thanh niên áo lam nội tông đệ tử Thi Âm Tông"],"blurb":"Thần thông ngũ quỷ của thanh niên áo lam, dùng lục khí hóa quỷ ảnh kết ấn công kích.","detail":"Thanh niên áo lam dùng lục khí hóa năm quỷ ảnh, kết thành lục ấn đánh về phía Vương Lâm. Năm quỷ ảnh bị cuồng phong do Vương Lâm vung tay tạo ra phá diệt.","nguon":["@c0896"]},{"id":"cu-ma-than-thong","name":"Cự Ma thần thông","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"thiên phú","hePhai":"Cự Ma Tộc","soHuu":["Đại hán Cự Ma Tộc thứ hai"],"blurb":"Thần thông của đại hán Cự Ma Tộc thứ hai dùng để mở đường rút lui cho thanh niên áo lam.","detail":"Đại hán Cự Ma Tộc thứ hai mở khe hở ở mi tâm, phát u quang tạo lốc xoáy sau lưng thanh niên áo lam. Lốc xoáy này được Vương Lâm nhận ra là thiên phú thần thông của Cự Ma Tộc.","nguon":["@c0896"]},{"id":"cu-ma-toc-thien-phu-than-thong","name":"Cự Ma tộc thiên phú thần thông","cn":"","loai":"than-thong","loaiLabel":"Thiên phú thần thông","phamCap":"thiên phú","hePhai":"Cự Ma Tộc","soHuu":["Đại hán Cự Ma Tộc thứ hai"],"blurb":"Thiên phú thần thông của Cự Ma Tộc, được dùng để tạo lốc xoáy dịch chuyển hoặc rút lui.","detail":"Trong lúc thanh niên áo lam bỏ chạy, Vương Lâm nhận ra lốc xoáy do đại hán Cự Ma Tộc tạo ra là thiên phú thần thông của Cự Ma Tộc. Thần thông này mở ra sau lưng thanh niên áo lam để đưa hắn rời khỏi chiến trường.","nguon":["@c0896"]},{"id":"tu-thai-ho-diep","name":"Tứ Thải Hồ Điệp","cn":"","loai":"than-thong","loaiLabel":"Thần thông / thủ quyết","phamCap":"chưa rõ","hePhai":"Huyền Bảo thượng nhân","soHuu":["Huyền Bảo thượng nhân","Vương Lâm"],"blurb":"Tứ Thải Hồ Điệp là thủ quyết thần thông từng được Huyền Bảo thượng nhân thi triển trong chiến tranh La Thiên và Liên Minh. Vương Lâm đã ghi nhớ toàn bộ thủ quyết nhưng thử mười ngày vẫn chưa tìm được cảm giác.","detail":"Trong lúc tới gần Thiên Vận tinh, Vương Lâm nhớ lại cảnh Huyền Bảo thượng nhân thi triển Tứ Thải Hồ Điệp. Hắn đã ghi nhớ toàn bộ thủ quyết, liên tục thử nghiệm suốt mười ngày nhưng chưa cảm nhận được điểm then chốt để thi triển thành công.","nguon":["@c0897"]},{"id":"nam-tinh-diem-co-than","name":"Năm tinh điểm Cổ Thần","cn":"","loai":"khac","loaiLabel":"Truyền thừa / dấu hiệu Cổ Thần","phamCap":"năm tinh vương tộc Cổ Thần","hePhai":"Cổ Thần","soHuu":["Vương Lâm"],"blurb":"Năm tinh điểm Cổ Thần là dấu hiệu truyền thừa Cổ Thần của Vương Lâm. Khi hắn điểm mi tâm, năm tinh điểm hiện ra rồi biến thành hạt châu hư ảo trước khi ẩn thành tia lửa nóng.","detail":"Vương Lâm kích phát mi tâm khiến năm tinh điểm Cổ Thần hiện ra. Dị tượng này liên quan truyền thừa năm tinh vương tộc Cổ Thần mà hắn đạt được, đồng thời nối với hạt châu hư ảo và chu tước ấn ký trong suy tính của hắn trước khi tiến vào Thiên Vận tinh.","nguon":["@c0897"]},{"id":"chu-tuoc-an-ky","name":"Chu tước ấn ký","cn":"","loai":"khac","loaiLabel":"Ấn ký / truyền thừa","phamCap":"chưa rõ","hePhai":"Tứ Thánh Tông / Chu Tước","soHuu":["Vương Lâm"],"blurb":"Chu tước ấn ký của Vương Lâm mang thiên địa viêm lực và tiếng phượng hót mơ hồ trong thần thức. Hắn suy đoán ấn ký này có quan hệ lớn với Hoàng Long chưởng môn và chu tước.","detail":"Sau khi năm tinh điểm Cổ Thần và hạt châu hư ảo biến mất, mi tâm Vương Lâm chỉ còn tia lửa nóng ẩn bên trong. Hắn liên hệ ấn ký này với thiên địa viêm lực, tiếng phượng hót, chu tước và lời Hoàng Long từng nói về thân phận Tứ Thánh Tông của mình.","nguon":["@c0897"]},{"id":"mot-quyen-loc-xoay-mau-den-cua-vuong-lam","name":"Một quyền lốc xoáy màu đen của Vương Lâm","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"khong-ro","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Một quyền nhục thân tạo âm bạo và lốc xoáy đen, được Vương Lâm dùng để nghênh kiếm khí của Lăng Thiên Hậu.","detail":"Khi Lăng Thiên Hậu phóng kiếm khí vào mình, Vương Lâm lùi vài bước rồi tung quyền. Quyền thế tạo âm bạo và lốc xoáy màu đen để va chạm với kiếm khí trước khi Thiên Vận Tử hóa giải cả hai bên.","nguon":["@c0898"]},{"id":"gio-bay-mau-cua-thien-van-tu","name":"Gió bảy màu của Thiên Vận Tử","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"khong-ro","hePhai":"Thiên Vận Tông","soHuu":["Thiên Vận Tử"],"blurb":"Thần thông bảy màu của Thiên Vận Tử, dùng để hóa giải xung đột giữa Vương Lâm và Lăng Thiên Hậu.","detail":"Thiên Vận Tử phất tay tạo một cơn gió nhẹ bảy màu chứa lực lượng kỳ dị. Cơn gió này hóa giải quyền của Vương Lâm và ngăn kiếm khí của Lăng Thiên Hậu, đồng thời thể hiện lập trường bảo vệ đệ tử trong sơn môn Thiên Vận Tông.","nguon":["@c0898"]},{"id":"tam-cuu-chi-kiem","name":"Tam Cửu Chi Kiếm","cn":"","loai":"kiem-quyet","loaiLabel":"Kiếm trận","phamCap":"không rõ","hePhai":"Vương Lâm","soHuu":["Vương Lâm"],"blurb":"Tam Cửu Chi Kiếm là kiếm trận do Vương Lâm gọi ra bằng hai mươi bảy phi kiếm ngân quang. Kiếm trận mang theo hồn phách và sát khí, được dùng để đối kháng nguyên thần kiếm của Lăng Thiên Hậu.","detail":"Trong trận trước các lão quái Thiên Vận Tông, Vương Lâm vỗ túi trữ vật gọi hai mươi bảy thanh phi kiếm, tạo thành Tam Cửu Chi Kiếm. Kiếm trận khiến Thiên Vận Tử, mỹ phụ luyện khí, Kỳ Mộng Đàm và lão nhân núi thịt đều nhận ra thực lực cùng bảo kiếm của hắn không tầm thường.","nguon":["@c0899","@c0945"],"tabs":{"tienTrinh":[{"chuong":"@c0945","loai":"thi triển","importance":"normal","giaiDoan":"Xuyên phá hắc mãng","text":"Tam cửu chi kiếm hóa thành kiếm trận hai mươi bảy kiếm, xuyên phá hắc mãng trong liên kích của bốn lão già áo xanh.","anchor":"Thần sắc của Vương Lâm như thường, há mồm phun ra một thứ"}]},"trangThai":"Vương Lâm đang dùng","aliases":["Đại kiếm kim quang"],"congNang":["Hóa hai mươi bảy kiếm thành kiếm võng để công phá mục tiêu @c0945"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c0945","tangDatToi":"Không rõ","trangThai":"đang dùng"}]},{"id":"ngu-cuu-kiem-tran","name":"Ngũ Cửu Kiếm Trận","cn":"","loai":"kiem-quyet","loaiLabel":"Kiếm trận","phamCap":"không rõ","hePhai":"Vương Lâm","soHuu":["Vương Lâm"],"blurb":"Ngũ Cửu Kiếm Trận là thế trận bốn mươi lăm phi kiếm của Vương Lâm. Hắn dùng kiếm trận này phối hợp Trảm La quyết để đối kháng Huyết Chú Kiếm của Lăng Thiên Hậu.","detail":"Sau Tam Cửu Chi Kiếm, Vương Lâm gọi thêm phi kiếm để thành tổng cộng bốn mươi lăm trường kiếm, xoay tròn thành lốc kiếm. Khi dung nhập Trảm La quyết vào trận, Ngũ Cửu Kiếm Trận giao phong trực diện với Minh kiếm — Huyết Chú Kiếm, khiến thiên địa biến sắc và buộc Thiên Vận Tử phải ngăn dư lực.","nguon":["@c0899"]},{"id":"minh-kiem-huyet-chu-kiem","name":"Minh kiếm — Huyết Chú Kiếm","cn":"","loai":"than-thong","loaiLabel":"Thần thông kiếm đạo","phamCap":"không rõ","hePhai":"Lăng Thiên Hậu","soHuu":["Lăng Thiên Hậu"],"blurb":"Minh kiếm — Huyết Chú Kiếm là thức Minh trong ba chữ thần thông kiếm đạo của Lăng Thiên Hậu. Ông thi triển thức này sau khi thừa nhận Vương Lâm đủ tư cách khiến mình dùng thần thông.","detail":"Lăng Thiên Hậu nói cả đời thần thông của mình chỉ có ba chữ Minh, Động, Phá, trong đó Minh kiếm là Huyết Chú Kiếm. Khi bốn nguyên thần kiếm bị kiếm trận và quyền phong của Vương Lâm ép lui, ông dùng thức này để giao phong với Ngũ Cửu Kiếm Trận hợp Trảm La quyết.","nguon":["@c0899"]},{"id":"minh-dong-pha","name":"Minh, Động, Phá","cn":"","loai":"than-thong","loaiLabel":"Hệ thần thông kiếm đạo","phamCap":"không rõ","hePhai":"Lăng Thiên Hậu","soHuu":["Lăng Thiên Hậu"],"blurb":"Minh, Động, Phá là ba chữ thần thông kiếm đạo mà Lăng Thiên Hậu nói là thần thông cả đời mình. Trong chương này ông mới thi triển thức Minh kiếm, tức Huyết Chú Kiếm.","detail":"Hệ thần thông này được Lăng Thiên Hậu nêu ra khi giao chiến với Vương Lâm. Thức đầu tiên là Minh kiếm — Huyết Chú Kiếm, đủ khiến tu sĩ xung quanh chấn động vì ngoài các trận với Thiên Vận Tử, Lăng Thiên Hậu hiếm khi vận dụng thần thông như vậy.","nguon":["@c0899"]},{"id":"tien-thuat-tung-dau-gia-o-quy-nhan-phuong-thi","name":"Tiên thuật từng đấu giá ở Quỷ Nhãn phường thị","cn":"","loai":"than-thong","loaiLabel":"Tiên thuật","phamCap":"Đầy đủ; bản không đầy đủ được xem là hạ phẩm","hePhai":"không rõ","soHuu":[],"blurb":"Một đạo tiên thuật đầy đủ từng được Quỷ Nhãn phường thị đưa ra bán đấu giá. Sự kiện này gây chấn động, khiến cả các lão quái tu vi bí hiểm cũng tự mình tới.","detail":"Hai đệ tử Thiên Vận Tông nhắc rằng Quỷ Nhãn phường thị từng nổi danh vì bán đấu giá một đạo tiên thuật đầy đủ. Với thân phận của họ, nhiều nhất cũng chỉ có thể chạm tới bản không đầy đủ, hạ phẩm, cho thấy đạo tiên thuật hoàn chỉnh có giá trị rất cao.","nguon":["@c0900"]},{"id":"quy-tac-mua-cam-ngo-nam-do","name":"Quy tắc mưa cảm ngộ năm đó","cn":"","loai":"khac","loaiLabel":"Quy tắc cảm ngộ","phamCap":"Không rõ","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Cảm ngộ quy tắc liên quan đến mưa mà Vương Lâm từng lĩnh hội, được vận dụng để tản mây trên bầu trời Tử Phong.","detail":"Trong đêm quan sát Tử Phong, Vương Lâm phất tay mang theo cảm ngộ quy tắc mưa, khiến mây đen hóa thành mưa nhỏ rồi nhanh chóng tiêu tán, để ánh trăng chiếu rõ ngọn núi và giúp hắn tiếp tục suy ngộ về động tĩnh.","nguon":["@c0901"]},{"id":"hoa-chi-quy-tac","name":"Hỏa chi quy tắc","cn":"","loai":"khac","loaiLabel":"Quy tắc","phamCap":"Không rõ","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Tầng quy tắc vận hành sâu bên trong ánh nến mà Vương Lâm nhìn thấy khi quan sát đến cực hạn.","detail":"Khi Vương Lâm nhìn xuyên ánh nến, cảnh tượng trong mắt hắn chuyển thành núi lửa rồi tiếp tục lộ ra vô số điểm nguyên lực giao thoa, va chạm theo trật tự. Hắn xác nhận đó là Hỏa chi quy tắc, từ đó chạm tới phỏng đoán về tầng căn nguyên sâu hơn quy tắc.","nguon":["@c0901"]},{"id":"sau-dao-phong-an","name":"Sáu đạo phong ấn","cn":"","loai":"bi-thuat","loaiLabel":"Phong ấn tu vi","phamCap":"Không rõ","hePhai":"Thiên Vận Tông","soHuu":["Triệu Hân Mộng"],"blurb":"Sáu đạo phong ấn trong cơ thể Triệu Hân Mộng dùng để áp chế tu vi chân chính. Nhờ lớp phong ấn này, tu vi nàng lộ ra ngoài chỉ khoảng Anh Biến hậu kỳ.","detail":"Vương Lâm nhìn ra trong cơ thể Triệu Hân Mộng có sáu đạo phong ấn, khiến tu vi thật của nàng bị ép xuống mức biểu hiện bên ngoài. Đây là cách nàng tự bảo vệ trước cấm kỵ đệ tử Thiên Vận Tông vượt Vấn Đỉnh rồi mất tích.","nguon":["@c0902"]},{"id":"phong-an-muoi-mot-dao-cua-ton-hong","name":"Phong ấn mười một đạo của Tôn Hồng","cn":"","loai":"bi-thuat","loaiLabel":"Phong ấn tu vi","phamCap":"Không rõ","hePhai":"Thiên Vận Tông, Xích hệ","soHuu":["Tôn Hồng"],"blurb":"Mười một đạo phong ấn trong cơ thể Tôn Hồng được Triệu Hân Mộng nêu như trường hợp che giấu tu vi sâu nhất mà nàng biết. Lớp phong ấn khiến tu vi bên ngoài của Tôn Hồng dừng ở Vấn Đỉnh trung kỳ.","detail":"Theo lời Triệu Hân Mộng, Tôn Hồng thuộc Xích hệ có mười một đạo phong ấn, đồng thời tự quấy nhiễu cảm ngộ để đồng bộ với tu vi bị phong. Nếu mở phong ấn, nàng có thể rất nhanh đạt Khuy Niết sơ kỳ.","nguon":["@c0902"]},{"id":"kiem-y-vien-co-truyen-thua","name":"Kiếm ý viễn cổ truyền thừa","cn":"","loai":"kiem-quyet","loaiLabel":"Kiếm ý","phamCap":"không rõ","hePhai":"không rõ","soHuu":["Vương Lâm","Hứa Lập Quốc"],"blurb":"Kiếm ý viễn cổ mà Hứa Lập Quốc được Vương Lâm cho ở cạnh để kế thừa. Hứa Lập Quốc cũng chủ động cảm ngộ nhằm tăng thực lực và tìm cơ hội thoát khỏi áp chế.","detail":"Trong chương 903, Vương Lâm cho phép Hứa Lập Quốc tạm thời không trở vào kiếm tiên mà ở cạnh mình để kế thừa kiếm ý. Hứa Lập Quốc ngoài mặt thuận phục nhưng trong lòng vẫn muốn cố tu luyện kiếm ý viễn cổ để một ngày thoát khỏi khống chế của Vương Lâm.","nguon":["@c0903"]},{"id":"song-duc-tien-quyet","name":"Âm Dương Song Dục quyết","cn":"","loai":"cong-phap","loaiLabel":"Công pháp","phamCap":"Không rõ","hePhai":"","soHuu":["Bạch Vi"],"aliases":["Song Dục Tiên Quyết"],"blurb":"Công pháp Bạch Vi thừa nhận đang tu luyện, liên hệ với trạng thái âm khí và biến hóa tâm tính, hành vi nữ tính của hắn.","detail":"Khi bị Vương Lâm hỏi công pháp, Bạch Vi phản ứng gay gắt như bị xúc phạm rồi thừa nhận tu luyện Song Dục Tiên Quyết. Công pháp này gắn với âm khí lưu chuyển trong kinh mạch Bạch Vi và biến hóa tâm tính, hành vi nữ tính rõ hơn trước, khiến Vương Lâm giữ nghi ngờ.","nguon":["@c0904"]},{"id":"an-ky-am-khi-kinh-mach-bach-vi","name":"Ấn ký âm khí trong kinh mạch Bạch Vi","cn":"","loai":"khac","loaiLabel":"Dấu hiệu công pháp","phamCap":"Không rõ","hePhai":"","soHuu":["Bạch Vi"],"blurb":"Ấn ký kỳ dị hình thành do âm khí lưu chuyển quá nhanh trong kinh mạch Bạch Vi, xuất hiện cực ngắn rồi biến mất.","detail":"Sau khi nghe tên công pháp Song Dục Tiên Quyết, Vương Lâm thấy âm khí trong kinh mạch Bạch Vi lưu chuyển nhanh, thoáng hình thành một ấn ký kỳ dị rồi biến mất. Vương Lâm lặng lẽ ghi nhớ hiện tượng này.","nguon":["@c0904"]},{"id":"cam-che-tran-phap-quy-nhan-thanh","name":"Cấm chế trận pháp Quỷ Nhãn Thành","cn":"","loai":"khac","loaiLabel":"Trận pháp","phamCap":"Không rõ","hePhai":"","soHuu":["Quỷ Nhãn Thành"],"blurb":"Cấm chế bảo vệ Quỷ Nhãn Thành; thần thức lướt qua không bị phát hiện, nhưng khi Vương Lâm bước vào bằng bản thể thì cấm chế lóe lên rồi tan vỡ.","detail":"Thành trì có dao động cấm chế nghiêm ngặt. Thần thức Vương Lâm lướt nhẹ qua không bị lộ, nhưng khi hắn bước thẳng vào bằng bản thể, cấm chế Quỷ Nhãn Thành kịch liệt lóe lên rồi trực tiếp tan vỡ, để hắn xuất hiện trên không trung thành.","nguon":["@c0904"]},{"id":"than-thuc-hoa-cu-long-tran-dao-tam-tu","name":"Thần thức hóa cự long của Trần Đạo Tam Tử","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"","soHuu":["Trần Nhất Tử"],"blurb":"Ba đạo thần thức ẩn sâu của Trần Đạo Tam Tử bùng nổ, hóa thành cự long và cơn lốc để vây khốn rồi định cắn nuốt thần thức đối phương.","detail":"Ba đạo thần thức ẩn núp sâu đậm của Trần Đạo Tam Tử bỗng bùng nổ, hóa thành cự long và cơn lốc vây khốn thần thức Vương Lâm. Chúng định cắn nuốt thần thức của hắn, nhưng Vương Lâm bắt lấy một đạo ném vỡ.","nguon":["@c0904"]},{"id":"hu-khong-trao-bop-nat-than-thuc","name":"Hư không trảo bóp nát thần thức","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Vương Lâm","soHuu":["Vương Lâm"],"blurb":"Thủ đoạn của Vương Lâm: tay phải hư không một trảo bắt lấy đạo thần thức đối phương, khiến nó bị lực thiên địa kéo tới rồi bóp nát.","detail":"Vương Lâm không cần chạm trực tiếp, chỉ dùng tay phải hư không bắt lấy đạo thần thức cuối cùng của Nhất Trần Tử. Thần thức như bị sức mạnh của thiên địa chèn ép và lực hút kéo tới trước mặt hắn rồi bị bóp nát, khiến chủ nhân phản phệ thổ huyết. Uy lực này khiến Trần Đạo Tam Tử nghi hắn đã đạt cảnh giới Tịnh Niết.","nguon":["@c0905"]},{"id":"tu-linh-tran","name":"Tụ linh trận","cn":"","loai":"khac","loaiLabel":"Trận pháp","phamCap":"Không rõ","hePhai":"Không rõ","soHuu":["Trần Đạo Tam Tử"],"blurb":"Tụ linh trận được bố trí quanh đình hóng mát phía bắc đại viện. Trận pháp giúp tiên khí trong đình tuần hoàn lâu dài, tạo nơi tiếp khách thanh tĩnh.","detail":"Trong buổi Nhất Trần Tử mời Vương Lâm, đình hóng mát bằng tiên ngọc được đặt tụ linh trận ở bốn phía. Nhờ trận này, tiên khí nơi đó được duy trì và lưu chuyển, phù hợp cho việc tiếp khách, uống rượu và luận đạo.","nguon":["@c0906"]},{"id":"thuy-linh-the","name":"Thủy Linh thể","cn":"","loai":"khac","loaiLabel":"Thể chất tu luyện","phamCap":"Thể chất trời sinh","hePhai":"Thủy","soHuu":["Linh Nhi"],"blurb":"Thủy Linh thể là thể chất trời sinh của Linh Nhi. Thể chất này khiến nàng cần được che chở vì dễ bị kẻ không có ý tốt bắt làm lô đỉnh.","detail":"Nhất Trần Tử cho biết Linh Nhi trời sinh Thủy Linh thể, nhiều phương diện đã được ông che giấu nhưng thanh âm vẫn khó giấu hết. Vì tư chất này có thể bị lợi dụng làm lô đỉnh, ông phải mang nàng bên người để bảo hộ.","nguon":["@c0906"]},{"id":"cam-che-phong-bach-vi","name":"Cấm chế phòng Bạch Vi","cn":"","loai":"khac","loaiLabel":"Cấm chế","phamCap":"Không rõ","hePhai":"","soHuu":["Bạch Vi"],"blurb":"Lớp cấm chế thần thức mỏng trong phòng Bạch Vi, rất khó nhận ra nhưng phản chấn cực mạnh khi bị chạm tới.","detail":"Cấm chế này tồn tại trong phòng Bạch Vi sau khi hắn biến mất. Vương Lâm dùng thần thức phát hiện, bị lực phản chấn bạo tăng ngăn lại rồi cưỡng ép phá bỏ, sau đó thấy trong phòng trống không.","nguon":["@c0907"]},{"id":"cam-che-thung-lung-phia-tay-quy-nhan-thanh","name":"Cấm chế thung lũng phía tây Quỷ Nhãn thành","cn":"","loai":"khac","loaiLabel":"Cấm chế","phamCap":"Không rõ","hePhai":"","soHuu":["Bạch Vi"],"blurb":"Cấm chế ẩn giấu thung lũng nơi Bạch Vi hiện thân với khí chất nam tử.","detail":"Cấm chế này gần như không dao động, che phủ một thung lũng cách Quỷ Nhãn thành mấy ngàn dặm về phía tây. Vương Lâm chỉ phát hiện được nhờ dung thần thức vào vô số giọt mưa sau khi thi triển Hoán Vũ.","nguon":["@c0907"]},{"id":"than-thong-thuat-tao-cuc-duong-cua-thien-van-tu","name":"Thần thông thuật tạo cực dương của Thiên Vận Tử","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"không rõ","hePhai":"Thiên Vận Tông","soHuu":["Thiên Vận Tử"],"blurb":"Thần thông bị Bạch Nguy nói là nguyên nhân tạo nên ngày cực dương hiếm thấy trên Thiên Vận Tinh. Biến cố này mở đầu cho thân thế cực dương, cực âm của Bạch Nguy.","detail":"Theo lời Bạch Nguy, cực dương năm đó không phải thiên tượng tự nhiên mà do Thiên Vận Tử dùng thần thông tạo thành. Từ ngày cực dương này, Bạch Nguy sinh ra trong hoàn cảnh đặc biệt, còn muội muội song sinh tiêu tán thân thể nhưng linh hồn hấp thụ cực âm và dung nhập vào hắn.","nguon":["@c0908"]},{"id":"nhat-chi-soan-thien-van","name":"Nhất Chỉ Soán Thiên Vận","aliases":["Một chỉ của Thiên Vận Tử","Một chỉ thần thông của Thiên Vận Tử","Một chỉ thay trời đổi vận"],"cn":"","loai":"than-thong","loaiLabel":"Đại thần thông","phamCap":"Đại thần thông thuật","hePhai":"Thiên Vận Tử tự cảm ngộ","soHuu":["Thiên Vận Tử"],"blurb":"Đại thần thông do Thiên Vận Tử tự cảm ngộ sáng tạo, lấy thiên địa nguyên lực ngoài Thiên Vận Tinh ngưng thành một ngón tay khổng lồ.","detail":"Khi Thiên Vận Tử ra tay từ Thiên Vận Tông, nguyên lực thiên địa bên ngoài Thiên Vận Tinh điên cuồng tụ lại, hóa thành ngón tay nghìn trượng từ hư ảo thành thực chất rồi hạ xuống tinh cầu. Chương nhấn mạnh thần thông này không phải Cổ Thần Nhất Chỉ mà là thuật do Thiên Vận Tử tự ngộ.","nguon":["@c0909"]},{"id":"co-than-nhat-chi","name":"Cổ Thần Nhất Chỉ","aliases":[],"cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Cổ Thần","soHuu":[],"blurb":"Thần thông Cổ Thần được nhắc tới để đối chiếu với ngón tay khổng lồ của Thiên Vận Tử.","detail":"Trong cảnh Thiên Vận Tử thi triển ngón tay khổng lồ, nguyên tác nói rõ đó tuyệt đối không phải Cổ Thần Nhất Chỉ, qua đó phân biệt quyền năng của Thiên Vận Tử với thần thông Cổ Thần.","nguon":["@c0909"]},{"id":"dai-tran-990-thong-thien-cac","name":"Đại trận 990 thông thiên các","cn":"","loai":"khac","loaiLabel":"Trận pháp","phamCap":"Không rõ","hePhai":"Đại La Kiếm Tông","soHuu":["Đại La Kiếm Tông"],"blurb":"Đại trận hợp bởi 990 tòa thông thiên các trong Đại La Kiếm Tông.","detail":"Trong Đại La Kiếm Tông, 990 tòa thông thiên các cùng hợp thành một đại trận khổng lồ hiếm thấy, tạo thành nền tảng phòng hộ và uy thế cho tông môn của Lăng Thiên Hậu.","nguon":["@c0910"]},{"id":"song-gon-bay-mau","name":"Sóng gợn bảy màu","cn":"","loai":"than-thong","loaiLabel":"Biến hóa thần thông","phamCap":"Không rõ","hePhai":"Thiên Vận Tử","soHuu":["Thiên Vận Tử"],"blurb":"Sóng gợn bảy màu là lớp lực lượng bảo hộ quanh đầu ngón tay trong một chỉ của Thiên Vận Tử. Khi bị giọt mưa đỏ của Hoán Vũ phá vỡ, nó biến hóa thành bảy đầu cực long nhiều màu vờn quanh đầu ngón tay.","detail":"Trong lúc Vương Lâm dùng Hoán Vũ Chi Tinh và hư ảnh Thanh Thủy hóa giọt mưa đỏ xuyên phá một chỉ, giọt mưa đỏ va vào lớp sóng gợn bảy màu bên ngoài đầu ngón tay. Lớp sóng gợn này bị phá tan rồi hóa thành bảy đầu cực long nhiều màu rít gào quanh đầu ngón tay, thể hiện tầng biến hóa phòng hộ của thần thông Thiên Vận Tử.","nguon":["@c0911"]},{"id":"phong-long-bay-mau","name":"Phong Long bảy màu","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Thiên Vận Tử","soHuu":["Thiên Vận Tử"],"blurb":"Thần thông gió bảy màu do Thiên Vận Tử phóng ra để truy kích Vương Lâm.","detail":"Thiên Vận Tử vung tay tạo gió mạnh và ánh sáng bảy màu ngưng tụ thành Phong Long thân vài trăm trượng. Bên trong Phong Long có linh hồn rồng chân chính, lao tới cắn nuốt Vương Lâm rồi bị Kỳ Lân đỏ thẫm của Lăng Thiên Hậu chặn đánh; dù sụp đổ, nó vẫn có thể tái ngưng tụ trong gió bảy màu.","nguon":["@c0912"]},{"id":"luc-luong-co-than-dung-hop-nguyen-luc","name":"Lực lượng Cổ Thần dung hợp nguyên lực","cn":"","loai":"than-thong","loaiLabel":"Chiến lực thân thể","phamCap":"Không rõ","hePhai":"Cổ Thần","soHuu":["Vương Lâm"],"blurb":"Cách Vương Lâm dung hợp nguyên lực với lực lượng Cổ Thần để đánh quyền phá thần thông của Thiên Vận Tử.","detail":"Vương Lâm vận chuyển nguyên lực trong cơ thể, dung hợp lực lượng Cổ Thần vào quyền thế đã chuẩn bị từ lâu. Liên tiếp các quyền khiến ngón tay khổng lồ lan đầy hồng quang rồi sụp đổ thành thiên địa nguyên lực.","nguon":["@c0912"]},{"id":"bon-thanh-kiem-nguyen-than","name":"Bốn thanh kiếm nguyên thần","cn":"","loai":"kiem-quyet","loaiLabel":"Kiếm đạo thần thông","phamCap":"Không rõ","hePhai":"Kiếm Tôn","soHuu":["Lăng Thiên Hậu"],"blurb":"Bốn thanh kiếm nguyên thần xoay quanh bên ngoài thân thể Lăng Thiên Hậu khi lão xuất hiện.","detail":"Khi Lăng Thiên Hậu cưỡi Kỳ Lân đỏ thẫm tới, bốn thanh kiếm nguyên thần xoay tròn ngoài thân, tỏa kiếm khí dữ dội xông thẳng trời cao. Chúng thể hiện kiếm đạo đặc trưng của Kiếm Tôn trong lúc lão can thiệp cuộc đối đầu với Thiên Vận Tử.","nguon":["@c0912"]},{"id":"sat-luc-khi-chan-chinh","name":"Sát Lục khí chân chính","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"không rõ","hePhai":"Thiên Vận Tử áo xám","soHuu":["Thiên Vận Tử áo xám"],"blurb":"Mười đạo Sát Lục khí thật sự do Thiên Vận Tử áo xám thi triển, khác xa bản không trọn vẹn Vương Lâm từng biết.","detail":"Mỗi đạo được luyện từ lượng Sát Lục khí khổng lồ sau khi người tu luyện dung nhập thân thể và nguyên thần vào đó. Khi biến hóa, mười đạo Sát Lục khí hóa thành mười bóng người nam nữ già trẻ, mỗi người lại phóng ra không dưới trăm vạn Sát Lục khí.","nguon":["@c0913"]},{"id":"hap-thu-luc-luong-anh-sang","name":"Hấp thu lực lượng ánh sáng","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"không rõ","hePhai":"Thiên Vận Tử áo xám","soHuu":["Thiên Vận Tử áo xám"],"blurb":"Thần thông khiến bóng tối trong trời đất tụ lại khi ánh sáng bị hút đi.","detail":"Vương Lâm nhận định Thiên Vận Tử áo xám đang hấp thu lực lượng ánh sáng, khiến hắc ám trong trời đất dồn vào tay và ngưng tụ thành một thanh kiếm nhỏ màu đen.","nguon":["@c0913"]},{"id":"pha-thien-thuc-thu-ba-kiem-dong-te-linh","name":"Phá Thiên thức thứ ba – Kiếm Đồng Tế Linh","cn":"","loai":"than-thong","loaiLabel":"Kiếm thức thần thông","phamCap":"Không rõ","hePhai":"Kiếm Đạo của Lăng Thiên Hậu","soHuu":["Lăng Thiên Hậu"],"blurb":"Kiếm thức do Lăng Thiên Hậu thi triển trong trận đối đầu Thiên Vận Tử áo xám. Kiếm đồng hiến tế vào Vũ Kiếm hình rắn để tăng thế kiếm phá khí Sát Lục.","detail":"Lăng Thiên Hậu dùng Phá Thiên thức thứ ba, khiến đứa bé đeo kiếm bộc phát kiếm khí rồi hiến tế vào con rắn lớn do Vũ Kiếm biến thành. Sau khi kiếm đồng tan thành sương xanh dung nhập, Vũ Kiếm hình rắn mang uy lực mạnh hơn để đánh tan nhiều đạo khí Sát Lục.","nguon":["@c0914"]},{"id":"te-kiem","name":"Tế Kiếm","cn":"","loai":"bi-thuat","loaiLabel":"Kiếm thuật nghi thức","phamCap":"Không rõ","hePhai":"Kiếm Đạo của Lăng Thiên Hậu","soHuu":["Lăng Thiên Hậu"],"blurb":"Nghi thức kiếm đạo do Lăng Thiên Hậu ra lệnh khi kiếm đồng sụp đổ thành sương xanh. Sương xanh dung nhập vào Tiên Kiếm hình rắn như hồn phách hiến tế.","detail":"Trong quá trình thi triển Phá Thiên thức thứ ba, Lăng Thiên Hậu dùng lệnh Tế Kiếm để đưa kiếm đồng vào Tiên Kiếm hình rắn. Nghi thức này khiến kiếm đồng trở thành phần hiến tế, gia tăng uy lực của Vũ Kiếm trong giao phong với khí Sát Lục.","nguon":["@c0914"]},{"id":"sat-luc-hoa-kiem","name":"Sát Lục Hóa Kiếm","cn":"","loai":"than-thong","loaiLabel":"Thần thông sát lục","phamCap":"Không rõ","hePhai":"Thiên Vận Tử áo xám","soHuu":["Thiên Vận Tử áo xám"],"blurb":"Thần thông gom vô số khí Sát Lục thành kiếm đỏ thẫm. Thiên Vận Tử áo xám dùng nó để lấy kiếm đối kiếm với Lăng Thiên Hậu.","detail":"Thiên Vận Tử áo xám điều động khí Sát Lục bốn phương ngưng tụ thành một thanh kiếm đỏ thẫm, sau đó tiếp tục bổ sung sát khí để tăng uy lực. Thanh kiếm này đối đầu trực diện với Kiếm Đạo của Lăng Thiên Hậu và gây ra va chạm dữ dội trong chương.","nguon":["@c0914"]},{"id":"kiem-dao-cua-lang-thien-hau","name":"Kiếm Đạo của Lăng Thiên Hậu","cn":"","loai":"cong-phap","loaiLabel":"Đạo pháp kiếm tu","phamCap":"Không rõ","hePhai":"Kiếm Tôn","soHuu":["Lăng Thiên Hậu"],"blurb":"Đạo pháp mà Lăng Thiên Hậu tự nhận cả đời chỉ tu. Trong chương, hắn dùng nguyên thần hóa thành hư ảnh kiếm, thể hiện cảnh giới kiếm đạo rất cao.","detail":"Lăng Thiên Hậu khẳng định cả đời làm bạn với kiếm và chỉ tu Kiếm Đạo. Hắn đã hiểu rõ quy tắc của Kiếm, dùng nguyên thần hóa thành hư ảnh kiếm và khiến kiếm của tu sĩ trên Thiên Vận Tinh cùng chấn động như cúng bái.","nguon":["@c0914"]},{"id":"kiem-than-kiem-ton-te-luyen","name":"Kiếm Thần / Kiếm Tôn tế luyện","cn":"","loai":"bi-thuat","loaiLabel":"Kiếm đạo bí pháp","phamCap":"Không rõ","hePhai":"Kiếm Đạo của Lăng Thiên Hậu","soHuu":["Lăng Thiên Hậu"],"blurb":"Bí pháp kiếm đạo gắn với lời tuyên bố lấy nguyên thần tu Kiếm Thần, lấy máu thịt tế Kiếm Tôn. Nó biểu hiện trạng thái ta là kiếm, kiếm là ta của Lăng Thiên Hậu.","detail":"Khi đối đầu thanh kiếm Sát Lục, Lăng Thiên Hậu mở khe ở mi tâm, để hắc mang bao phủ và dùng nguyên thần cùng máu thịt tế luyện kiếm đạo. Diễn biến này dẫn tới nguyên thần của hắn hóa thành hư ảnh kiếm, nâng thế đối kháng với Thiên Vận Tử áo xám.","nguon":["@c0914"]},{"id":"dai-phien-cam","name":"Đại Phiến Cấm","cn":"","loai":"khac","loaiLabel":"Cấm chế","phamCap":"không rõ","hePhai":"cấm chế","soHuu":["Vương Lâm"],"blurb":"Cấm chế được Vương Lâm bố trí quanh nơi tạm trú trên Đại La tinh.","detail":"Sau khi được phong trưởng lão Đại La Kiếm Tông và tự chọn một tòa tháp ngoài ngàn dặm, Vương Lâm ngồi xuống bên ngoài tháp rồi vung tay tạo Đại Phiến Cấm để che chở khu vực mình chuẩn bị luyện hóa tia cực dương.","nguon":["@c0916"]},{"id":"bac-dau-that-tinh-luc","name":"Bắc Đẩu Thất Tinh lực","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"không rõ","hePhai":"Thiên Vận thuật","soHuu":["Thiên Vận Tử"],"blurb":"Thần thông Thiên Vận tử dùng để gọi lực Bắc Đẩu chống bàn tay hư vô.","detail":"Khi bàn tay từ hư vô chộp tới, Thiên Vận tử gọi Bắc Đẩu Thất Tinh lực khiến cầu vồng bảy sắc giáng xuống, hóa thành lốc xoáy bảy màu với bảy điểm sáng. Thần thông này vẫn không ngăn được bàn tay vô hình.","nguon":["@c0916"]},{"id":"that-tinh-toai-tien","name":"Thất Tinh toái tiên","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"không rõ","hePhai":"Thiên Vận thuật","soHuu":["Thiên Vận Tử"],"blurb":"Đòn phá giải bảy điểm sáng trong lốc xoáy bảy màu để tạo chấn động ngăn địch.","detail":"Thiên Vận tử khiến bảy điểm sáng trong lốc xoáy bảy màu đồng loạt sụp đổ, sinh ra lực chấn động nhằm chống bàn tay hư vô. Dù vậy, bàn tay vẫn xuyên qua lực cản và tiếp tục chộp tới hắn.","nguon":["@c0916"]},{"id":"thien-van-thuat","name":"Thiên Vận thuật","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"đại thần thông","hePhai":"Thiên Vận tông","soHuu":["Thiên Vận Tử"],"blurb":"Đại thần thông của Thiên Vận tử, hơn vạn năm chưa từng thi triển.","detail":"Trước bàn tay hư vô tạo nguy cơ sống chết, Thiên Vận tử thi triển Thiên Vận thuật, triệu ra la bàn hư ảo khổng lồ trong tinh không với vô số phù văn ấn ký. Đây là thần thông đạt đại thành trong đời hắn và được dùng để suy diễn cách chống lại biến cố vượt ngoài tính toán.","nguon":["@c0916"]},{"id":"phung-thien-thua-van","name":"Phụng Thiên Thừa Vận","cn":"","loai":"than-thong","loaiLabel":"Pháp quyết","phamCap":"không rõ","hePhai":"Thiên Vận thuật","soHuu":["Thiên Vận Tử"],"blurb":"Pháp quyết thúc động la bàn hư ảo trong Thiên Vận thuật.","detail":"Thiên Vận tử dùng Phụng Thiên Thừa Vận để khiến la bàn hư ảo khổng lồ xoay chuyển, tạo uy thế như nghịch chuyển trời đất và điên đảo Càn Khôn trong lúc suy diễn bàn tay hư vô.","nguon":["@c0916"]},{"id":"thien-vat-thuat-mo-sau-dao-phong-an","name":"Thiên Vật Thuật – Mở sáu đạo phong ấn","cn":"","loai":"than-thong","loaiLabel":"Thần thông phong ấn","phamCap":"không rõ","hePhai":"Thiên Vận thuật","soHuu":["Thiên Vận Tử"],"blurb":"Thần thông mở sáu đạo phong ấn để tăng lực suy diễn của la bàn hư ảo.","detail":"Khi cho rằng tốc độ quay của la bàn chưa đủ, Thiên Vận tử thúc Thiên Vật Thuật mở sáu đạo phong ấn, khiến la bàn hư ảo không ngừng bành trướng trong tinh không.","nguon":["@c0916"]},{"id":"la-ban-den-trang-cua-thien-van-tu","name":"La bàn đen trắng của Thiên Vận Tử","cn":"","loai":"than-thong","loaiLabel":"Thần thông suy tính","phamCap":"Không rõ","hePhai":"Thiên Vận thuật","soHuu":["Thiên Vận Tử"],"blurb":"Hư ảnh la bàn đen trắng bao phủ ngoài Thiên Vận tinh, được Thiên Vận Tử dùng để suy tính cách chống bàn tay khổng lồ.","detail":"Khi bàn tay khổng lồ ép tới Thiên Vận tinh, Thiên Vận Tử vận dụng hư ảnh la bàn đen trắng để điên cuồng tính toán. Hắn không tính ra toàn bộ đầu đuôi của bàn tay, nhưng tính ra phương án chống cự tạm thời bằng cách cho nó hấp thu nguyên lực.","nguon":["@c0917"]},{"id":"phan-than-hu-ao-cua-thien-van-tu","name":"Phân thân hư ảo của Thiên Vận Tử","cn":"","loai":"than-thong","loaiLabel":"Thần thông phân thân nguyên lực","phamCap":"Không rõ","hePhai":"Thiên Vận thuật","soHuu":["Thiên Vận Tử"],"blurb":"Thần thông tạo nhiều thân ảnh hư ảo giống Thiên Vận Tử để bàn tay khổng lồ hấp thu nguyên lực.","detail":"Thiên Vận Tử liên tục điểm mi tâm, thả ra từng đợt thân ảnh hư ảo giống mình để bàn tay nuốt lấy thiên địa nguyên lực. Cách này ban đầu nhằm thử giới hạn hấp thu của bàn tay, nhưng khi bàn tay nghịch chuyển phản kích, lượng phân thân hư ảo khiến tổn thất nguyên lực của hắn tăng mạnh.","nguon":["@c0917"]},{"id":"phong-an-va-tran-phap-trong-dai-la-tinh","name":"Phong ấn và trận pháp trong Đại La tinh","cn":"","loai":"khac","loaiLabel":"Phong ấn trận pháp","phamCap":"Không rõ","hePhai":"Đại La tinh","soHuu":["Lăng Thiên Hậu"],"blurb":"Các lớp phong ấn và trận pháp trên đường vào sâu trong Đại La tinh, không thể chặn ánh sáng vô hình.","detail":"Khi Lăng Thiên Hậu bỏ chạy vào lòng Đại La tinh, những phong ấn cùng trận pháp trên đường đều không có tác dụng ngăn cản ánh sáng vô hình truy đuổi. Điều này cho thấy thứ ánh sáng kia vượt ngoài phương thức phòng hộ thông thường tại Đại La tinh.","nguon":["@c0917"]},{"id":"te-hoa-trong-dai-la-tinh","name":"Tế hỏa trong Đại La tinh","cn":"","loai":"khac","loaiLabel":"Tàn lưu luyện hóa","phamCap":"Không rõ","hePhai":"Tu chân tông Côn Hư","soHuu":["Hư Linh thượng nhân","Lăng Thiên Hậu"],"blurb":"Hỏa lực còn lại trong Đại La tinh từ lần Hư Linh Thượng Nhân luyện hóa tinh cầu năm xưa.","detail":"Lăng Thiên Hậu chạy tới nơi sâu nhất của Đại La tinh để dựa vào tế hỏa do Hư Linh Thượng Nhân của Tu chân tông Côn Hư để lại. Hắn tin sức nóng này có thể giúp chống lại nguy cơ, nhưng ánh sáng vô hình vẫn đuổi tới và hóa thành bàn tay khổng lồ.","nguon":["@c0917"]},{"id":"luc-bon-nguyen","name":"Lực bổn nguyên","cn":"","loai":"than-thong","loaiLabel":"Bổn nguyên","phamCap":"không rõ","hePhai":"Vương Lâm","soHuu":["Vương Lâm"],"blurb":"Lực bổn nguyên là lực lượng thưa thớt của Vương Lâm, phần lớn đến từ Chiến tự thiếp và một phần nhỏ từ cảm ngộ tại phù tộc trên Chu Tước tinh. Ở chương này, nó trở thành chìa khóa mở lại Thiên Nghịch.","detail":"Ngày thứ mười một, con mắt thứ ba của Vương Lâm tự mở và phóng hồng quang chứa lực bổn nguyên. Lực lượng này dung nhập vào đồ án mặt trời trên hạt châu Thiên Nghịch, giống chìa khóa mở ra không gian Thiên Nghịch và kéo thần thức Vương Lâm tới trước cánh cửa lớn.","nguon":["@c0918"]},{"id":"suc-dia-thanh-thon","name":"Súc địa thành thốn","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Thần thông di chuyển được nhắc khi Vương Lâm rời Đại La tinh.","detail":"Trong chương này Vương Lâm không thi triển Súc địa thành thốn khi rời Đại La tinh, nhưng tốc độ phi hành của hắn vẫn không chậm.","nguon":["@c0919"]},{"id":"tien-bi-diet-than","name":"Tiên Bi Diệt Thần","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"khong-ro","hePhai":"khong-ro","soHuu":["Phù Phong tử"],"blurb":"Thần thông do Phù Phong tử thi triển khi mở đầu giao chiến với Vương Lâm trong tinh không.","detail":"Khi đối đầu Vương Lâm, Phù Phong tử gọi ra hư ảnh bia đá khổng lồ phát kim quang, sau đó khiến hư ảnh lao tới và đè xuống đối thủ.","nguon":["@c0920"]},{"id":"tran-phap-hop-luc-bay-ho-ve-ao-den","name":"Trận pháp hợp lực bảy hộ vệ áo đen","cn":"","loai":"khac","loaiLabel":"Trận pháp","phamCap":"khong-ro","hePhai":"khong-ro","soHuu":["Bảy người áo đen hộ vệ lão già núi thịt"],"blurb":"Trận pháp phối hợp của bảy hộ vệ áo đen dưới trướng Phù Phong tử.","detail":"Bảy hộ vệ dồn nguyên lực lần lượt vào người đứng đầu, khiến người này biến lớn và đánh ra hổ đen nhằm tấn công Đầu to.","nguon":["@c0920"]},{"id":"quyen-luc-co-than","name":"Quyền lực Cổ Thần","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"chiến kỹ Cổ Thần","hePhai":"Cổ Thần","soHuu":["Vương Lâm"],"blurb":"Một quyền dung hợp tu vi Khuy Niết trung kỳ đỉnh phong của Vương Lâm với lực lượng Cổ Thần. Chiêu này huyễn hóa hư ảnh cánh tay Cổ Thần gần trăm trượng, phá bia đá và hóa giải chín dấu ấn của Trần Phong.","detail":"Trong trận với Trần Phong, Vương Lâm tung quyền khiến hư ảnh Cổ Thần như cùng đánh ra với hắn, chứng minh chiến lực đủ áp đảo tu sĩ Tịnh Niết sơ kỳ trong giao phong trực diện.","nguon":["@c0921"]},{"id":"do-la-phu-tran","name":"Đồ La Phù trần","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"sát chiêu","hePhai":"Trần Phong","soHuu":["Trần Phong"],"blurb":"Sát chiêu của Trần Phong, dùng tinh hoa máu thịt toàn thân co rút để ngưng tụ ánh sáng nguy hiểm từ mi tâm. Chiêu này gây cảm giác nguy cơ cho Vương Lâm nhưng bị Diệt Thần Mâu phá tan.","detail":"Khi bị Vương Lâm ép vào thế nguy, Trần Phong khiến thân thể gầy như xương khô để thi triển Đồ La Phù trần. Ánh sáng mi tâm bị Diệt Thần Mâu hư ảo đánh sụp chỉ sau thời gian ngắn.","nguon":["@c0921"]},{"id":"khuy-niet-trung-ky","name":"Khuy Niết trung kỳ","cn":"","loai":"khac","loaiLabel":"Cảnh giới","phamCap":"Khuy Niết trung kỳ","hePhai":"Tu chân","soHuu":["Vương Lâm"],"blurb":"Khuy Niết trung kỳ là cảnh giới hiện tại của Vương Lâm trong thời gian tạm cư tại Thủy Linh Tinh. Sau ba ngày tĩnh tọa, cảnh giới này được củng cố vững chắc.","detail":"Tại cung điện phía Đông Thủy Linh Tinh, Vương Lâm tĩnh tọa ba ngày để ổn định tu vi Khuy Niết trung kỳ. Khi phối hợp với thân thể Cổ Thần, hắn tự đánh giá bản thân có thể miễn cưỡng giao chiến với tu sĩ Tịnh Niết trung kỳ.","nguon":["@c0922"]},{"id":"than-the-co-than","name":"Thân thể Cổ Thần","cn":"","loai":"luyen-the","loaiLabel":"Thể chất huyết mạch","phamCap":"Cổ Thần","hePhai":"Cổ Thần","soHuu":["Vương Lâm"],"blurb":"Thân thể Cổ Thần là nền tảng chiến lực đặc biệt của Vương Lâm. Nhờ thân thể này, hắn cảm nhận được khí tức Cổ Thần bị che giấu trong thanh quang thuẫn.","detail":"Sau khi củng cố Khuy Niết trung kỳ, Vương Lâm dùng thân thể Cổ Thần để ước lượng chiến lực trước tu sĩ Tịnh Niết trung kỳ. Cũng nhờ thân phận và cảm ứng Cổ Thần, hắn nhận ra trong thanh quang tiểu thuẫn có một tia khí tức Cổ Thần bị che đậy, dẫn tới suy đoán pháp bảo này do một Cổ Thần khác thời thái cổ tế luyện.","nguon":["@c0922"]},{"id":"vuong-toc-co-than-luc","name":"Vương tộc Cổ Thần lực","cn":"","loai":"than-thong","loaiLabel":"Lực lượng huyết mạch","phamCap":"vương tộc Cổ Thần","hePhai":"Cổ Thần","soHuu":["Vương Lâm"],"blurb":"Lực lượng Cổ Thần thuộc vương tộc mà Vương Lâm vận dụng khi mở Thanh quang thuẫn. Lực này giúp hắn tách thần niệm Thanh Long Thánh Hoàng khỏi khí tức Cổ Thần trong thuẫn.","detail":"Trong quá trình phá phong ấn Thanh quang thuẫn, Vương Lâm ngưng tụ lực lượng Cổ Thần vương tộc trên đầu ngón tay để công kích khí xoáy bên dưới ấn ký Thanh Long. Nhờ lực lượng này, thần niệm đang dung hòa với khí tức Cổ Thần được tách ra và lời cầu cứu của Thanh Long Thánh Hoàng hiện rõ.","nguon":["@c0923"]},{"id":"than-thong-bao-menh-cua-co-than-xa-la","name":"Thần thông bảo mệnh của Cổ Thần xa lạ","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Bảo mệnh thần thông của Bát tinh Cổ Thần","hePhai":"Cổ Thần","soHuu":["Cổ Thần xa lạ","Vương Lâm"],"blurb":"Thần thông phong ấn bên trong Thanh quang thuẫn, do Cổ Thần xa lạ để lại. Muốn mở ra cần tấm thuẫn hấp thu đủ sức mạnh của trời đất.","detail":"Vương Lâm biết được từ tin tức truyền thừa của Thanh quang thuẫn rằng vật này nếu hấp thu đủ sức mạnh trời đất thì có thể mở ra thần thông bảo mệnh. Vì đây là thần thông của một Cổ Thần có tám tinh điểm và gần đạt Cửu tinh, hắn đánh giá uy lực của nó rất đáng kinh động.","nguon":["@c0924"]},{"id":"than-thong-bia-da-tu-quang-cua-phu-phong-tu","name":"Thần thông bia đá tử quang của Phù Phong Tử","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"không rõ","hePhai":"","soHuu":["Phù Phong tử"],"blurb":"Thần thông do Phù Phong Tử thi triển khi thử uy lực Thanh quang thuẫn. Tử quang ngưng tụ thành bia đá chứa nhiều ấn ký và thiên địa nguyên lực để trấn áp đối thủ.","detail":"Theo yêu cầu của Vương Lâm, Phù Phong Tử bấm quyết, vận chuyển tử quang tạo thành bia đá, lấy sức mạnh toàn lực đánh về phía Vương Lâm. Thanh quang thuẫn tự động nghênh đỡ, phá nát bia đá và hấp thu sạch thiên địa nguyên lực bên trong, khiến thần thông này trở thành phép thử năng lực phòng hộ và hấp thu của tấm thuẫn.","nguon":["@c0924"]},{"id":"than-no-lac-an","name":"Thần nô lạc ấn","cn":"","loai":"khac","loaiLabel":"Cơ chế Cổ Thần","phamCap":"","hePhai":"Cổ Thần","soHuu":[],"blurb":"Lạc ấn do Cổ Thần đích thân hạ xuống trên Thần nô, có thể tồn tại qua vô số luân hồi.","detail":"Lạc ấn Thần nô là dấu ấn Cổ Thần hạ xuống linh hồn Thần nô, cho phép Cổ Thần nhận thiên địa lực từ dân chúng Thái cổ thông qua người này. Lạc ấn có thể theo linh hồn Thần nô qua vô số luân hồi. Ở Linh nhi, lạc ấn cũ đã bị dấu ấn của Vương Lâm thay thế khi hắn dung nhập, khiến sinh tử nàng gắn liền với nhịp tim hắn.","nguon":["@c0927"]},{"id":"thuy-canh","name":"Thủy Cảnh","cn":"","loai":"khac","loaiLabel":"Đại cảnh giới","phamCap":"","hePhai":"Tu Chân Giới","soHuu":[],"blurb":"Một trong ba đại cảnh giới cổ truyền Cực, Đạo, Thủy của Tu Chân Giới; mức huyền ảo đứng đầu và người đạt được cực hiếm.","detail":"Thủy Cảnh là một trong ba đại cảnh giới cổ truyền của Tu Chân Giới, không bá đạo bằng Cực Cảnh, không thần bí bằng Đạo Cảnh, nhưng mức huyền ảo đứng đầu và cực hiếm người tiến vào. Trạng thái an bình mơ hồ của Vương Lâm khi thổ nạp, cảm nhận mặt trời mọc lặn, được xác nhận là đang ở bên bờ Thủy Cảnh; thời gian trong loại Thủy Cảnh này rất ngắn ngủi.","nguon":["@c0927"]},{"id":"dao-canh","name":"Đạo Cảnh","cn":"","loai":"khac","loaiLabel":"Đại cảnh giới","phamCap":"","hePhai":"Tu Chân Giới","soHuu":[],"blurb":"Một trong ba đại cảnh giới cổ truyền Cực, Đạo, Thủy của Tu Chân Giới, nổi bật tính thần bí.","detail":"Đạo Cảnh được nêu cùng Cực Cảnh và Thủy Cảnh như một trong ba đại cảnh giới cổ truyền của Tu Chân Giới. So với hai cảnh giới còn lại, Đạo Cảnh mang tính thần bí nhất.","nguon":["@c0927"]},{"id":"tho-nap","name":"Thổ nạp","cn":"","loai":"khac","loaiLabel":"Pháp tu luyện","phamCap":"","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Pháp thổ nạp cơ bản; Vương Lâm ngồi khoanh chân trên tảng đá thổ nạp và từ đó chìm vào cảm ngộ.","detail":"Thổ nạp là cách tu luyện qua hít thở điều tức. Trên Thủy Linh tinh, Vương Lâm ngồi khoanh chân trên tảng đá nhìn trời, chìm vào thổ nạp, rồi đi sâu vào trạng thái cảm ngộ kỳ dị chính là bên bờ Thủy Cảnh.","nguon":["@c0927"]},{"id":"ba-canh-cuc-dao-thuy","name":"Ba cảnh Cực, Đạo, Thủy","loai":"khac","loaiLabel":"Hệ cảnh giới đặc thù","phamCap":"","hePhai":"","soHuu":[],"blurb":"Ba cảnh lớn Cực, Đạo, Thủy được cho là có thể chia thành biến hóa linh và thần.","detail":"Được trình bày như ba cảnh lớn có thể phân thành sáu nhánh: linh cực, thần cực, linh đạo, thần đạo, linh thủy, thần thủy. Hiểu biết về Cực khá rõ, còn Đạo và Thủy phần lớn vẫn mơ hồ.","nguon":["@c0928"]},{"id":"than-thuy","name":"Thần thủy","loai":"khac","loaiLabel":"Trạng thái Thủy Cảnh","phamCap":"","hePhai":"","soHuu":[],"blurb":"Trạng thái cao trong Thủy Cảnh, gắn khả năng tự sinh thần thông mang đạo thiên địa.","detail":"Được nhắc qua ghi chép của luyện khí sĩ Thượng cổ Lưu Văn, liên hệ với khả năng tự sinh thần thông mang đạo của thiên địa. Thật giả đã thành lời đồn khó xác định.","nguon":["@c0928"]},{"id":"linh-thuy","name":"Linh thủy","loai":"khac","loaiLabel":"Trạng thái Thủy Cảnh","phamCap":"","hePhai":"","soHuu":[],"blurb":"Trạng thái mà người bước vào Thủy Cảnh từ Viễn cổ gần như chỉ đạt được ngắn ngủi.","detail":"Được nói là trạng thái khiến linh lực biến hóa nghiêng trời lệch đất trong thời gian rất ngắn; phần lớn người bước vào Thủy Cảnh từ Viễn cổ chỉ chạm tới thoáng qua.","nguon":["@c0928"]},{"id":"than-thong-cua-luu-van","name":"Thần thông của Lưu Văn","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"","soHuu":["Lưu Văn"],"blurb":"Thần thông chưa ai nghe qua của Lưu Văn, uy lực khó tưởng tượng.","detail":"Được mô tả là chưa ai nghe thấy hay gặp qua, uy lực lớn gần như không thể tưởng tượng và ẩn chứa đạo của thiên địa.","nguon":["@c0928"]},{"id":"tan-da","name":"Tàn Dạ","cn":"","aliases":["Tàn Dạ Chi Lực","lực lượng sinh ra khi đêm tàn","Lực tàn đêm"],"loai":"than-thong","loaiLabel":"Thần thông/cảm ngộ quy tắc","phamCap":"Chưa rõ","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Lực lượng Vương Lâm lĩnh ngộ từ khoảnh khắc mặt trời mọc phá tan màn đêm trên biển. Khi Phù Phong tử xông vào phạm vi cảm ngộ, lực lượng này khiến hắn như hóa thành đêm tối bị xé nát.","detail":"Tàn Dạ là lực lượng sinh ra từ cảnh bình minh trên biển sau hơn hai tháng Vương Lâm chờ đợi và cảm ngộ. Trong lần đầu hiển lộ, nó khiến Phù Phong tử chịu cảm giác thân thể và nguyên thần bị xé rách, đồng thời nghiền nát các thủ đoạn phòng ngự bằng thiên địa nguyên lực của tu sĩ Tịnh Niết.","thuocTinh":"Cảm ngộ từ thời khắc đêm tàn, mặt trời mọc và ánh sáng phá tan bóng tối.","uyLuc":"Có thể áp chế Phù Phong tử trong phạm vi cảm ngộ, xuyên phá gió lốc nguyên lực và khiến quả cầu nguyên lực Tịnh Niết sụp đổ.","dacDiem":"Gắn với hình tượng mặt trời rực sáng xé nát màn đêm, khiến người bước vào cảm giác bản thân hóa thành đêm tối bị phá vỡ.","congNang":["Xé rách cảm giác đêm tối của đối thủ, gây thương tổn lên thân thể và nguyên thần @c0929","Xuyên phá gió lốc thiên địa nguyên lực phòng ngự @c0929","Làm quả cầu nguyên lực Tịnh Niết sụp đổ khi va chạm @c0929"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c0929","tangDatToi":"Lĩnh ngộ lần đầu từ bình minh trên biển","trangThai":"đang tu"}],"tabs":{"tienTrinh":[{"chuong":"@c0929","loai":"xuất hiện","importance":"major","giaiDoan":"Lĩnh ngộ từ bình minh","text":"Vương Lâm nắm bắt khoảnh khắc mặt trời phá tan màn đêm, để lực lượng tàn dạ dung nhập vào thân thể và hiển lộ uy năng trước Phù Phong tử.","anchor":"Cuối cùng một giây, nó toàn bộ dung nhập vào cơ thể Vương Lâm."}]},"trangThai":"đang hiển lộ","capNhatToi":"@c0929","dinhDanh":"goc","nguon":["@c0929"]},{"id":"than-thong-hap-thu-thien-dia-nguyen-luc-cua-tinh-niet","name":"Thần thông hấp thu thiên địa nguyên lực của Tịnh Niết","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Thần thông cảnh giới","phamCap":"Tịnh Niết","hePhai":"","soHuu":["Phù Phong tử"],"blurb":"Thần thông Phù Phong tử thi triển bằng cách hấp thu thiên địa nguyên lực, ngưng thành quả cầu hủy diệt. Hắn dùng nó để chống lại hình tượng “mặt trời” do lực lượng tàn dạ của Vương Lâm tạo ra.","detail":"Trong lúc bị lực lượng tàn dạ uy hiếp, Phù Phong tử vận chuyển năng lực của tu sĩ Tịnh Niết, hút thiên địa nguyên lực hội tụ thành một quả cầu nguyên lực. Quả cầu này được hắn xem là hy vọng phá “mặt trời” để giữ mạng, nhưng cuối cùng sụp đổ trước lực lượng vô biên của bình minh phá đêm.","thuocTinh":"Thiên địa nguyên lực của cảnh giới Tịnh Niết.","uyLuc":"Khi ngưng tụ, uy thế khiến Trần Đạo Tam Tử và những người quan sát phải lùi lại, đồng thời gây chấn động lan khắp Thủy Linh tinh khi va chạm.","dacDiem":"Hội tụ nguyên lực thành quả cầu hủy diệt để công kích trực diện mục tiêu.","congNang":["Hấp thu thiên địa nguyên lực và ngưng tụ thành quả cầu công kích @c0929","Tạo chấn động lớn khi va chạm với lực lượng tàn dạ @c0929"],"nguoiTu":[{"ten":"Phù Phong tử","tuChuong":"@c0929","tangDatToi":"Thi triển quả cầu nguyên lực Tịnh Niết","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c0929","loai":"thi triển","importance":"normal","giaiDoan":"Đối kháng Tàn Dạ","text":"Phù Phong tử hấp thu thiên địa nguyên lực ngưng thành quả cầu hủy diệt để phá “mặt trời”, nhưng quả cầu nguyên lực sụp đổ khi va chạm với lực lượng tàn dạ.","anchor":"Chỉ có phá mặt trời này ta mới có thể giữ được mạng!"}]},"trangThai":"đang hiển lộ","capNhatToi":"@c0929","dinhDanh":"goc","nguon":["@c0929"]},{"id":"tam-cam-thuat","name":"Tâm Cấm thuật","cn":"","aliases":[],"loai":"bi-thuat","loaiLabel":"Cấm thuật","phamCap":"không rõ","hePhai":"cấm chế","soHuu":["Vương Lâm"],"blurb":"Cấm thuật được Vương Lâm dùng để gia cố phong ấn cung điện trước khi luyện hóa Ngân Y Luyện Thi.","detail":"Vương Lâm điểm mi tâm, thả tơ đen hóa thành cấm chế để tăng cường phong tỏa cung điện, phối hợp với nhiều tầng cấm chế và la bàn truyền nhân Phá Diệt Cấm.","dinhDanh":"goc","congNang":["Thả tơ đen hóa thành cấm chế để gia cố phong ấn cung điện @c0931"],"trangThai":"đang dùng","capNhatToi":"@c0931","tabs":{"tienTrinh":[]},"nguon":["@c0931"]},{"id":"thi-ve","name":"Thi vệ","cn":"","aliases":[],"loai":"bi-thuat","loaiLabel":"Thuật luyện thi","phamCap":"không rõ","hePhai":"Tiên Đế Thanh Sương","soHuu":["Tiên Đế Thanh Sương","Vương Lâm"],"blurb":"Thuật trong ngọc giản của Tiên Đế Thanh Sương, vốn dùng để luyện thi vệ từ người bị giết.","detail":"Vương Lâm không có đủ tài liệu đã tuyệt tích nên không luyện đủ Thi vệ theo nguyên thuật, mà chỉ lấy thủ đoạn khống chế trong đó để luyện hóa Ngân Y Luyện Thi.","dinhDanh":"goc","nguonGoc":"Ngọc giản của Tiên Đế Thanh Sương","congNang":["Dùng thủ đoạn khống chế xác chết để luyện hóa Ngân Y Luyện Thi @c0931"],"trangThai":"được Vương Lâm vận dụng một phần","capNhatToi":"@c0931","tabs":{"tienTrinh":[]},"nguon":["@c0931"]},{"id":"dai-tran-phong-ho-tinh-cau","name":"Đại trận phòng hộ tinh cầu","cn":"","aliases":[],"loai":"khac","loaiLabel":"Trận pháp","phamCap":"chưa rõ","hePhai":"Thủy Linh tinh","soHuu":["Trần Đạo Tam Tử"],"blurb":"Trận phòng hộ bao quanh Thủy Linh tinh. Trần Đạo Tam Tử dùng ba lệnh bài màu đen kích hoạt ba tầng hào quang sóng gợn màu đen để chống Tư Đồ Nam.","detail":"Đại trận được mở khi Tư Đồ Nam dùng thần thức Tịnh Niết sơ kỳ ép toàn tinh cầu. Ba thành viên Trần Đạo Tam Tử cùng lấy lệnh bài màu đen, tạo ba tầng phòng hộ bao phủ Thủy Linh tinh nhưng lần lượt bị Tư Đồ Nam công phá.","congNang":["Tạo ba tầng hào quang màu đen như sóng gợn bao phủ Thủy Linh tinh để phòng hộ @c0932"],"tabs":{"tienTrinh":[{"chuong":"@c0932","loai":"xuất hiện","importance":"major","giaiDoan":"mở trận phòng hộ","text":"Trần Đạo Tam Tử dùng ba lệnh bài màu đen kích hoạt ba tầng phòng hộ quanh Thủy Linh tinh để chống Tư Đồ Nam.","anchor":"Trong thời gian ngắn, toàn bộ bên ngoài Thủy Linh tinh liền có ba tầng hào quang màu đen như sóng gợn, bao phủ Thủy Linh tinh cực kỳ chặt chẽ!"}]},"capNhatToi":"@c0932","nguon":["@c0932"]},{"id":"trai-diet","name":"Trai diệt","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Thần thông chỉ pháp","phamCap":"chưa rõ","hePhai":"Tư Đồ Nam","soHuu":["Tư Đồ Nam"],"blurb":"Chỉ pháp của Tư Đồ Nam sau khi cải thiện hệ thống thần thông. Khi thi triển, nó tạo lốc xoáy hấp thu sức mạnh thiên địa và phá tầng phòng hộ đầu tiên của Thủy Linh tinh.","detail":"Tư Đồ Nam thi triển Trai diệt trong lúc áp sát Thủy Linh tinh. Lốc xoáy do chỉ pháp này tạo ra va chạm với hào quang màu đen, khiến tầng phòng hộ đầu tiên sụp đổ.","congNang":["Tạo lốc xoáy hấp thu sức mạnh thiên địa để công phá phòng hộ @c0932"],"tabs":{"tienTrinh":[{"chuong":"@c0932","loai":"thi triển","importance":"major","giaiDoan":"phá tầng thứ nhất","text":"Tư Đồ Nam dùng Trai diệt đánh vào đại trận và phá tầng hào quang màu đen đầu tiên.","anchor":"Phía bên kia, đạo ánh sáng màu đen giờ phút này kịch liệt chớp lóe, bỗng nhiên “phịch” một tiếng sụp đổ!"}]},"capNhatToi":"@c0932","nguon":["@c0932"]},{"id":"nhat-chi-thien-dia-tich-that-can-khon","name":"Nhất Chỉ Thiên Địa, Tịch Thất Càn Khôn","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Thần thông chỉ pháp","phamCap":"chưa rõ","hePhai":"Tư Đồ Nam","soHuu":["Tư Đồ Nam"],"blurb":"Chỉ pháp Tư Đồ Nam dùng sau Trai diệt. Nó tạo lốc xoáy lớn hấp thu lực lượng trong tinh không để tiếp tục công phá đại trận phòng hộ Thủy Linh tinh.","detail":"Trong lúc phá trận, Tư Đồ Nam thi triển Nhất Chỉ Thiên Địa, Tịch Thất Càn Khôn để hình thành lốc xoáy lớn hơn, hấp thu lực lượng tinh không như hố đen. Thần thông này mở đường cho Tịch Diệt biến nén ép thiên địa nguyên lực.","congNang":["Tạo lốc xoáy lớn hấp thu lực lượng trong tinh không để công phá phòng hộ @c0932"],"tabs":{"tienTrinh":[{"chuong":"@c0932","loai":"thi triển","importance":"major","giaiDoan":"tiếp tục phá trận","text":"Tư Đồ Nam thi triển Nhất Chỉ Thiên Địa, Tịch Thất Càn Khôn để tạo lốc xoáy hấp thu lực lượng tinh không nhằm tiếp tục công phá phòng hộ.","anchor":"Lốc xoáy không chút ngừng lại, trực tiếp chạm vào tầng ánh sáng màu đen cuối cùng."}]},"capNhatToi":"@c0932","nguon":["@c0932"]},{"id":"tich-diet-bien","name":"Tịch Diệt biến","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Biến hóa thần thông","phamCap":"chưa rõ","hePhai":"Tư Đồ Nam","soHuu":["Tư Đồ Nam"],"blurb":"Biến hóa trong chỉ pháp của Tư Đồ Nam. Nó nén ép thiên địa nguyên lực trong lốc xoáy, khiến sức công phá tăng mạnh khi đánh vào phòng hộ Thủy Linh tinh.","detail":"Tịch Diệt biến thể hiện thủ đoạn thêm bước biến vào vận dụng thiên địa nguyên lực. Tư Đồ Nam dùng nó làm lốc xoáy thu nhỏ và cắn nuốt tầng phòng hộ thứ hai, rồi tiếp tục chạm vào tầng cuối cùng.","congNang":["Nén ép thiên địa nguyên lực trong lốc xoáy để tăng sức công phá @c0932"],"tabs":{"tienTrinh":[{"chuong":"@c0932","loai":"thi triển","importance":"major","giaiDoan":"nén nguyên lực phá trận","text":"Tư Đồ Nam dùng Tịch Diệt biến nén ép thiên địa nguyên lực, khiến lốc xoáy cắn nuốt tầng phòng hộ thứ hai và chạm tới tầng cuối cùng.","anchor":"Lốc xoáy không chút ngừng lại, trực tiếp chạm vào tầng ánh sáng màu đen cuối cùng."}]},"capNhatToi":"@c0932","nguon":["@c0932"]},{"id":"tich-diet","name":"Tịch Diệt","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Thần thông","phamCap":"chưa rõ","hePhai":"Tư Đồ Nam","soHuu":["Tư Đồ Nam"],"blurb":"Một trong các thần thông Tư Đồ Nam từng chuyên môn điều chỉnh sau bế quan. Chương này nhắc nó trong mạch cải thiện hệ thống thần thông của hắn.","detail":"Tư Đồ Nam nhắc Tịch Diệt cùng Hóa Ma và Hoàng Tuyền khi nói về các thần thông đã được hắn điều chỉnh, làm nền cho việc thi triển Tịch Diệt biến trong phá trận.","nguon":["@c0932"]},{"id":"hoa-ma","name":"Hóa Ma","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Thần thông","phamCap":"chưa rõ","hePhai":"Tư Đồ Nam","soHuu":["Tư Đồ Nam"],"blurb":"Thần thông nằm trong nhóm chiêu pháp Tư Đồ Nam nhắc là đã điều chỉnh sau lần bế quan trước. Chương này chỉ nhắc tên trong hệ thống thần thông của hắn.","detail":"Hóa Ma được nhắc cùng Tịch Diệt và Hoàng Tuyền như một phần bộ thần thông mà Tư Đồ Nam từng cải thiện, chưa có diễn tả thi triển trực tiếp trong chương này.","nguon":["@c0932"]},{"id":"luc-luong-quy-tac","name":"Lực lượng quy tắc","cn":"","aliases":[],"loai":"khac","loaiLabel":"Cơ chế thần thông","phamCap":"liên quan Toái Niết","hePhai":"chưa rõ","soHuu":[],"blurb":"Cơ chế vận dụng thiên địa nguyên lực cao hơn hấp và ngưng. Khi thêm biến, nguyên lực bị nén ép thành lực lượng kỳ dị mà tu sĩ Toái Niết gọi là lực lượng quy tắc.","detail":"Chương này giải thích tầng vận dụng thiên địa nguyên lực trong thần thông: cấp thấp thiên về hấp và ngưng, còn cao hơn cần biến để hình thành lực lượng quy tắc. Tàn Dạ của Vương Lâm được nêu như ví dụ thuộc loại này.","congNang":["Nén ép và biến hóa thiên địa nguyên lực thành lực lượng kỳ dị trong thần thông @c0932"],"tabs":{"tienTrinh":[{"chuong":"@c0932","loai":"hé lộ tầng-chiêu","importance":"normal","giaiDoan":"giải thích cơ chế biến","text":"Chương này phân biệt hấp, ngưng và biến trong vận dụng thiên địa nguyên lực, đồng thời nêu Tàn Dạ của Vương Lâm thuộc loại lực lượng quy tắc.","anchor":"Trên thực tế thần thông Tàn Dạ Vương Lâm tự nghĩ ra, chính là thuộc về loại lực lượng quy tắc."}]},"capNhatToi":"@c0932","nguon":["@c0932"]},{"id":"hoang-tuyen-chi","name":"Hoàng Tuyền Chỉ","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"khong-ro","hePhai":"","soHuu":["Tư Đồ Nam"],"blurb":"Hoàng Tuyền Chỉ là chỉ pháp Tư Đồ Nam dùng để đối phó Phù Phong tử trước cung điện Vương Lâm.","detail":"Sau khi được Tư Đồ Nam cải thiện từ nền tảng Hoàng Tuyền Nhị Chỉ, chỉ phong mang tử khí nồng đậm kèm một tia sinh cơ, tự thành âm dương và có uy lực mạnh đến mức ép Phù Phong tử bị thương phải lùi.","thuocTinh":"Tử khí kèm sinh cơ, tự thành âm dương","uyLuc":"Ép Phù Phong tử lùi và khiến hắn biến sắc khi thần thông tiếp tục biến hóa.","dacDiem":"Là Hoàng Tuyền Nhị Chỉ đã được Tư Đồ Nam cải thiện.","congNang":["Tấn công bằng chỉ phong mang tử khí và sinh cơ, áp chế đối thủ trong giao chiến @c0933"],"nguoiTu":[{"ten":"Tư Đồ Nam","tuChuong":"@c0933","tangDatToi":"","trangThai":"dang-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c0933","loai":"thi triển","importance":"normal","giaiDoan":"Áp chế Phù Phong tử","text":"Tư Đồ Nam thi triển Hoàng Tuyền Chỉ đã cải thiện để đánh lui Phù Phong tử trước cung điện Vương Lâm.","anchor":"Hoàng Tuyền Nhị Chỉ sau khi được Tư Đồ Nam cải thiện dĩ nhiên có uy lực cực mạnh."}]},"capNhatToi":"@c0933","nguon":["@c0933"]},{"id":"hoang-tuyen-nhi-chi","name":"Hoàng Tuyền Nhị Chỉ","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"khong-ro","hePhai":"","soHuu":["Tư Đồ Nam"],"blurb":"Hoàng Tuyền Nhị Chỉ là nền tảng chỉ pháp được Tư Đồ Nam cải thiện thành Hoàng Tuyền Chỉ uy lực mạnh.","detail":"Trong trận trước cung điện Vương Lâm, Hoàng Tuyền Nhị Chỉ được nhắc như căn cơ của chỉ pháp đã được cải thiện, khiến Hoàng Tuyền Chỉ tự thành âm dương và uy lực tăng mạnh.","dacDiem":"Được Tư Đồ Nam cải thiện thành biến hóa Hoàng Tuyền Chỉ trong giao chiến.","congNang":["Làm nền tảng cho Hoàng Tuyền Chỉ sau cải thiện của Tư Đồ Nam @c0933"],"nguoiTu":[{"ten":"Tư Đồ Nam","tuChuong":"@c0933","tangDatToi":"","trangThai":"dang-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c0933","loai":"hé lộ tầng-chiêu","importance":"normal","giaiDoan":"Nền tảng được cải thiện","text":"Hoàng Tuyền Nhị Chỉ được nêu là cơ sở đã được Tư Đồ Nam cải thiện để tạo uy lực cực mạnh.","anchor":"Hoàng Tuyền Nhị Chỉ sau khi được Tư Đồ Nam cải thiện dĩ nhiên có uy lực cực mạnh."}]},"capNhatToi":"@c0933","nguon":["@c0933"]},{"id":"khon-tien-chi","name":"Khốn Tiên chỉ","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"khong-ro","hePhai":"","soHuu":["Tư Đồ Nam"],"blurb":"Khốn Tiên chỉ là thần thông Tư Đồ Nam dùng để vây trói nữ thi áo bạc.","detail":"Tư Đồ Nam thi triển Khốn Tiên chỉ tạo vòng tròn tử mang, hóa thành vô số quầng sáng co rút nhằm trói buộc nữ thi áo bạc, nhưng bị cây kéo do nàng phun ra phá tan từng tầng.","thuocTinh":"Tử mang, quầng sáng trói buộc","uyLuc":"Có thể tạo nhiều tầng quầng sáng co rút vây đối thủ.","congNang":["Tạo vòng sáng và quầng sáng co rút để vây trói mục tiêu @c0933"],"nguoiTu":[{"ten":"Tư Đồ Nam","tuChuong":"@c0933","tangDatToi":"","trangThai":"dang-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c0933","loai":"thi triển","importance":"normal","giaiDoan":"Vây nữ thi áo bạc","text":"Tư Đồ Nam dùng Khốn Tiên chỉ để vây nữ thi áo bạc nhưng quầng sáng bị cây kéo của nàng phá vỡ.","anchor":"Nhưng người con gái này cũng không đơn giản, há mồm phun ra một cây kéo vờn quanh thân thể."}]},"capNhatToi":"@c0933","nguon":["@c0933"]},{"id":"cam-che-trong-cung-dien-vuong-lam","name":"Cấm chế trong cung điện Vương Lâm","cn":"","loai":"khac","loaiLabel":"Cấm chế","phamCap":"khong-ro","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Cấm chế trong cung điện Vương Lâm lao ra khi Tư Đồ Nam áp sát nơi Vương Lâm luyện thi.","detail":"Các cấm chế từ cung điện tràn ra dày đặc với khí thế muốn phong ấn Tư Đồ Nam, nhưng phần lớn bị lốc xoáy hóa sóng gợn của hắn phá tan.","congNang":["Lao ra phong tỏa và công kích người áp sát cung điện Vương Lâm @c0933"],"tabs":{"tienTrinh":[{"chuong":"@c0933","loai":"thi triển","importance":"normal","giaiDoan":"Chặn Tư Đồ Nam","text":"Cấm chế trong cung điện Vương Lâm tràn ra muốn phong ấn Tư Đồ Nam nhưng bị sóng gợn lốc xoáy phá tan phần lớn.","anchor":"Tất cả mọi cấm chế đụng tới sóng gợn này đều đồng loạt sụp đổ."}]},"capNhatToi":"@c0933","nguon":["@c0933"]},{"id":"son-dong-nhat-chi","name":"Sơn Động Nhất Chỉ","aliases":["Nhất Chỉ Sơn Động"],"cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Chưa rõ","hePhai":"","soHuu":["Tư Đồ Nam"],"blurb":"Thần thông của Tư Đồ Nam, có thể từ một chỉ dẫn động sơn hồn để công kích đối thủ.","detail":"Ở lần thử đầu, Tư Đồ Nam dùng Nhất Chỉ Sơn Động nhưng bị lực thân thể của Vương Lâm phá vỡ. Khi thi triển bản đầy đủ, hắn ngưng tụ hồn tất cả núi trên Thủy Linh tinh vào một chỉ, tạo uy thế khiến thiên địa chấn động.","dinhDanh":"goc","congNang":["Ngưng tụ sơn hồn trên Thủy Linh tinh vào một chỉ công kích @c0934"],"nguoiTu":[{"ten":"Tư Đồ Nam","tuChuong":"@c0934","tangDatToi":"Bản đầy đủ","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c0934","loai":"thi triển","importance":"major","giaiDoan":"Bản đầy đủ","text":"Tư Đồ Nam thi triển Sơn Động Nhất Chỉ, ngưng tụ hồn tất cả núi trên Thủy Linh tinh để luận bàn với Vương Lâm.","anchor":"Đây dĩ nhiên là hồn tất cả những ngọn núi trên Thủy Linh tinh này"}]},"capNhatToi":"@c0934","nguon":["@c0934"]},{"id":"quyen-co-than","name":"Quyền Cổ Thần","cn":"","loai":"than-thong","loaiLabel":"Thần thông thân thể","phamCap":"Chưa rõ","hePhai":"Cổ Thần","soHuu":["Vương Lâm"],"blurb":"Đòn quyền dựa trên lực thân thể Cổ Thần của Vương Lâm, khi đánh ra hiện hư ảnh cánh tay Cổ Thần khổng lồ.","detail":"Vương Lâm dùng Quyền Cổ Thần để đối kháng Sơn Động Nhất Chỉ của Tư Đồ Nam. Một quyền này làm hiện hư ảnh cánh tay Cổ Thần, tạo xung kích khiến thiên địa chấn động và biển trên Thủy Linh tinh dậy sóng.","dinhDanh":"goc","congNang":["Hiện hư ảnh cánh tay Cổ Thần và đối cứng thần thông sơn hồn @c0934"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c0934","tangDatToi":"Thi triển trong luận bàn","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c0934","loai":"thi triển","importance":"major","giaiDoan":"Đối kháng Sơn Động Nhất Chỉ","text":"Vương Lâm đánh ra quyền Cổ Thần, hiện hư ảnh cánh tay Cổ Thần để đối cứng thần thông của Tư Đồ Nam.","anchor":"Phảng phất một quyền này chính là một cú đánh giận dữ của Cổ Thần!"}]},"capNhatToi":"@c0934","nguon":["@c0934"]},{"id":"y-canh-luan-hoi","name":"Ý Cảnh Luân Hồi","cn":"","loai":"khac","loaiLabel":"Ý cảnh","phamCap":"Chưa rõ","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Ý cảnh được nhắc trong hồi tưởng về giai đoạn Vương Lâm hóa phàm và tìm lại chính mình.","detail":"Tư Đồ Nam khi nhìn lại hành trình của Vương Lâm đã nhắc tới việc Vương Lâm sau một lần hóa phàm tìm lại chính mình và cảm ngộ Ý Cảnh Luân Hồi.","dinhDanh":"goc","congNang":["Gắn với quá trình hóa phàm, tìm lại bản thân và cảm ngộ luân hồi của Vương Lâm @c0934"],"tabs":{"tienTrinh":[{"chuong":"@c0934","loai":"nhắc tới","importance":"bridge","giaiDoan":"Hồi tưởng hành trình Vương Lâm","text":"Ý Cảnh Luân Hồi được nhắc khi Tư Đồ Nam hồi tưởng quá trình Vương Lâm hóa phàm và tìm lại chính mình.","anchor":"Sau khi hóa phàm một lần nữa tìm về chính mình, cảm ngộ Ý Cảnh Luân Hồi."}]},"capNhatToi":"@c0934","nguon":["@c0934"]},{"id":"song-tu-lo-dinh-chong-doc","name":"Song tu lô đỉnh chống độc","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Không rõ","hePhai":"Không rõ","soHuu":["Tư Đồ Nam"],"blurb":"Phương pháp Tư Đồ Nam dùng để kéo dài mạng sống khi trúng Dục Tiên Dục Tử.","detail":"Tư Đồ Nam dùng song tu với nữ tu lô đỉnh để giữ tu vi không tan và khiến độc tố luôn dừng ở giai đoạn Dục Tiên, nhờ đó sống sót đến hiện tại dù độc vốn có thể làm hình thần câu diệt sau bảy ngày.","dinhDanh":"goc","nguonGoc":"Do Tư Đồ Nam vận dụng để chống Dục Tiên Dục Tử.","congNang":["Giữ độc tố Dục Tiên Dục Tử ở giai đoạn Dục Tiên, giúp người trúng độc kéo dài sinh cơ."],"nguoiTu":[{"ten":"Tư Đồ Nam","tuChuong":"@c0935","tangDatToi":"Không rõ","trangThai":"đang dùng để áp chế độc"}],"tabs":{"tienTrinh":[{"chuong":"@c0935","loai":"xuất hiện","importance":"major","giaiDoan":"Chống Dục Tiên Dục Tử","text":"Tư Đồ Nam tiết lộ phương pháp song tu lô đỉnh là lý do hắn giữ được mạng dưới độc Tiên Giới.","anchor":"Như vậy độc tố thủy chung bảo trì ở giai đoạn Dục Tiên, như thế mới kéo dài tới bây giờ!"}]},"capNhatToi":"@c0935","nguon":["@c0935"]},{"id":"dai-tran-thien-van-tong","name":"Đại trận Thiên Vận tông","cn":"","loai":"khac","loaiLabel":"Trận pháp","phamCap":"Không rõ","hePhai":"Thiên Vận tông","soHuu":["Thiên Vận tông","Thiên Vận Tử"],"blurb":"Đại trận trên Thiên Vận tinh được mở khi Thiên Vận Tử phát thiệp mời vào động phủ Tiên nhân.","detail":"Đại trận của Thiên Vận tông mở ra trên Thiên Vận tinh, đánh dấu việc Thiên Vận Tử chính thức gửi thiệp mời cho các lão quái đủ tư cách tiến vào vùng đất Yêu Linh.","dinhDanh":"goc","congNang":["Hỗ trợ Thiên Vận Tử phát thiệp mời tới các lão quái đủ tư cách vào vùng đất Yêu Linh."],"tabs":{"tienTrinh":[{"chuong":"@c0935","loai":"xuất hiện","importance":"normal","giaiDoan":"Mở trận phát thiệp","text":"Đại trận Thiên Vận tông mở ra khi Thiên Vận Tử gửi thiệp mời mở động phủ Tiên nhân.","anchor":"Ngày hôm nay, theo đại trận của Thiên Vận tông trên Thiên Vận tinh mở ra, Thiên Vận tử tự thân viết mấy cái thiệp mời phất tay áo vung ra."}]},"capNhatToi":"@c0935","nguon":["@c0935"]},{"id":"tien-thuat-cua-thien-van-tu","name":"Tiên thuật của Thiên Vận tử","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Thần thông","phamCap":"khong-ro","hePhai":"Thiên Vận tử","soHuu":["Thiên Vận tử"],"blurb":"Hệ tiên thuật làm nên danh tiếng của Thiên Vận tử. Chương nhấn mạnh hắn gần như rất ít dùng pháp bảo mà vẫn có thể chấn động trời đất bằng tiên thuật.","detail":"Thiên Vận tử vốn nổi danh là đại thần thông giả hiếm khi dùng pháp bảo. Việc hắn đạp đinh ba đen tới Triều tịch càng khiến người chứng kiến chú ý tới sự khác thường, vì thường ngày hắn chủ yếu dựa vào vô số tiên thuật.","dinhDanh":"goc","capNhatToi":"@c0936","tabs":{"tienTrinh":[]},"nguon":["@c0936"]},{"id":"may-tia-than-thong","name":"Mây tía thần thông","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Thần thông","phamCap":"khong-ro","hePhai":"khong-ro","soHuu":["Hà di"],"blurb":"Mây tía do thần thông biến thành, chở Hà di và bốn thiếu nữ tới Triều tịch. Nó xuất hiện trong tinh không như phương tiện di chuyển của nhóm nữ tu.","detail":"Mây tía xuất hiện tại khu vực Triều tịch, phía trên là một người phụ nữ trung niên đẹp và phía sau là bốn thiếu nữ. Công dụng được thấy rõ là chở nhóm này đi trong tinh không.","dinhDanh":"goc","capNhatToi":"@c0936","tabs":{"tienTrinh":[]},"nguon":["@c0936"]},{"id":"kiem-quang-cua-lang-thien-hau","name":"Kiếm quang của Lăng Thiên Hậu","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Thần thông kiếm khí","phamCap":"khong-ro","hePhai":"Đại La Kiếm Tông","soHuu":["Lăng Thiên Hậu"],"blurb":"Kiếm quang mở đường khi Lăng Thiên Hậu tới Triều tịch. Sự xuất hiện của hắn khiến tinh không tràn ngập kiếm khí.","detail":"Khi Lăng Thiên Hậu cưỡi kỳ lân đỏ thẫm tới, kiếm khí tràn ngập tinh không, vạn đạo kiếm quang đi trước. Đây là biểu hiện kiếm đạo gắn với thân phận Kiếm Tôn của hắn.","dinhDanh":"goc","capNhatToi":"@c0936","tabs":{"tienTrinh":[]},"nguon":["@c0936"]},{"id":"dung-nhap-vao-trong-thien-dia","name":"Dung nhập vào trong thiên địa","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"","soHuu":["Hư Không Tử"],"blurb":"Thần thông Hư Không Tử dùng khi xuất hiện trước hố đen Đông Hải Triều Tịch, biểu hiện bằng cách hòa vào thiên địa rồi bước ra từ tinh không.","detail":"Hư Không Tử hiện thân bằng thủ đoạn dung nhập vào trong thiên địa, khí tức và cách xuất hiện khiến Vương Lâm nhận ra thần thông của ông vượt xa tu sĩ thông thường. Thần thông này gắn với lần Hư Không Tử can dự vào chuyện giữa Lăng Thiên Hậu và Thiên Vận Tử tại cửa vào vùng đất Yêu Linh.","nguon":["@c0938"]},{"id":"toai-niet","name":"Toái Niết","cn":"","aliases":[],"loai":"khac","loaiLabel":"Cảnh giới","phamCap":"","hePhai":"","soHuu":["Hư Không Tử"],"blurb":"Cảnh giới được Tư Đồ Nam nhận ra từ khí tức của Hư Không Tử, tạo áp lực lớn cho những người có mặt trước hố đen.","detail":"Khi Hư Không Tử xuất hiện, Tư Đồ Nam lẩm bẩm nhận ra đối phương ở cấp Toái Niết. Khí tức này khiến Vương Lâm kinh hãi và cho thấy Hư Không Tử là tồn tại cấp cao trong Liên minh, đủ sức đứng ra can thiệp chuyện giữa Lăng Thiên Hậu và Thiên Vận Tử.","nguon":["@c0938"]},{"id":"hon-diet","name":"Hồn diệt","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Thần thông tập thể","phamCap":"","hePhai":"Bộ lạc Luyện Hồn","soHuu":["Âu Dương Hoa","Bộ lạc Luyện Hồn"],"blurb":"Mệnh lệnh kiêm thủ đoạn tập thể của bộ lạc Luyện Hồn, do Âu Dương Hoa phát ra trong trận vây đô thành Hỏa Yêu.","detail":"Sau khi Hạt Kim bị Thập Tam giết, Âu Dương Hoa ra lệnh Hồn diệt. Mấy trăm vạn tộc nhân Luyện Hồn đồng loạt phóng cờ và hồn phách, khiến sương đen bao phủ trời đất, đè ép đô thành Hỏa Yêu và buộc phe trong thành phải đầu hàng.","nguon":["@c0938"]},{"id":"than-thong-vuong-toc-phan-hoa","name":"Thần thông vương tộc phân hoá","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Thần thông Cổ Thần","phamCap":"","hePhai":"Cổ Thần","soHuu":["Đồ Ti"],"blurb":"Thần thông Cổ Thần được nhắc trong kế hoạch năm xưa của Đồ Ti liên quan đến cây đinh ba.","detail":"Đồ Ti vốn đặt cây đinh ba trên một tinh cầu hóa thành ba ngọn núi để mượn sơn hồn toàn tinh cầu ngưng tụ khí linh. Ông dự định sau khi thần thông vương tộc phân hoá hoàn tất sẽ quay lại lấy pháp bảo, nhưng cuối cùng một đi không về, để lại tiếc nuối trong ký ức mà Vương Lâm cảm nhận được.","nguon":["@c0938"]},{"id":"bat-diet-linh-quyet","name":"Bất diệt linh quyết","cn":"","loai":"cong-phap","loaiLabel":"Công pháp","phamCap":"","hePhai":"","soHuu":["Vương Nguy","Kiếm linh"],"blurb":"Công pháp do Vương Nguy truyền cho kiếm linh trong Tiên phủ Yêu Linh chi địa.","detail":"Kiếm linh đã tu Bất diệt linh quyết tới tầng thứ tám và đang tiến vào tầng thứ chín, được Hồ Quyên đánh giá là rất có nghị lực và có khả năng sắp đột phá.","nguon":["@c0939"]},{"id":"tien-gioi-chi-tran","name":"Tiên giới chi trận","cn":"","loai":"khac","loaiLabel":"Truyền tống trận","phamCap":"Cổ trận Tiên giới","hePhai":"Tiên giới","soHuu":[],"blurb":"Truyền tống trận cổ ẩn dưới thảo nguyên cấm chế trong Yêu Linh chi địa.","detail":"Tiên giới chi trận có nguồn gốc từ thời Tiên giới chưa sụp đổ, bị che giấu dưới khu cấm chế khổng lồ. Dùng phương thức đặc thù cùng tín vật có thể tiến vào một trong năm Tiên phủ của Yêu Linh chi địa; cơ chế Tiên phủ thứ năm liên quan việc mở đủ bốn Tiên phủ bên ngoài.","nguon":["@c0939"]},{"id":"cam-che-thao-nguyen-yeu-linh-chi-dia","name":"Cấm chế thảo nguyên Yêu Linh chi địa","cn":"","loai":"khac","loaiLabel":"Cấm chế","phamCap":"","hePhai":"","soHuu":[],"blurb":"Khu cấm chế khổng lồ ẩn dưới bình nguyên cỏ xanh trong Yêu Linh chi địa.","detail":"Cấm chế này che giấu Tiên giới chi trận bên dưới thảo nguyên. Nếu bị mở ra, nó có oai lực hủy thiên diệt địa; khu vực này từng khiến chi nhánh Luyện Hồn bộ lạc phải từ bỏ vì Hồn phiên mất uy lực, hồn phách bị áp chế và tiêu tan khi cưỡng ép xuất ra.","nguon":["@c0939"]},{"id":"cam-che-tien-phu-cua-vuong-lam","name":"Cấm chế Tiên phủ của Vương Lâm","cn":"","loai":"khac","loaiLabel":"Cấm chế","phamCap":"","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Hệ thống cấm chế còn lại trong Tiên phủ thứ tư của Vương Lâm.","detail":"Tiên phủ thứ tư vẫn còn vô số cấm chế chưa bị phá. Vương Lâm giao thạch bàn và chỉ lại các chỗ cấm chế từng phá giải để Tư Đồ Nam cùng nhóm cao thủ vào Tiên phủ phá cấm, hướng tới vị trí trung tâm.","nguon":["@c0939"]},{"id":"cuu-chuyen-luyen-tien-quyet","name":"Cửu Chuyển Luyện Tiên quyết","cn":"","aliases":[],"loai":"cong-phap","loaiLabel":"Cấm pháp / công pháp","phamCap":"không rõ","hePhai":"Tử hệ Thiên Vận Tông; Luyện Hồn Tông","soHuu":["Tứ sư tỷ của Tử hệ Thiên Vận Tông","Vương Lâm","Luyện Hồn Tông"],"blurb":"Cửu Chuyển Luyện Tiên quyết là pháp môn Tứ sư tỷ Tử hệ Thiên Vận Tông từng truyền cho Vương Lâm. Đến chương này, Vương Lâm thác ấn nó thành đệ nhất cấm pháp của Luyện Hồn Tông.","detail":"Pháp môn này được Vương Lâm dùng làm nền tảng trọng yếu khi xây dựng hệ thống tu luyện cho Luyện Hồn Tông. Nếu tu luyện tới cực hạn, nó sinh ra xoắn ốc khí có uy lực lớn.","dinhDanh":"goc","nguonGoc":"Tứ sư tỷ của Tử hệ Thiên Vận Tông từng truyền cho Vương Lâm.","uyLuc":"Tu luyện tới cực hạn có thể sinh xoắn ốc khí uy lực lớn.","dacDiem":"Được lập thành đệ nhất cấm pháp của Luyện Hồn Tông.","congNang":["Làm nền cho đệ tử Luyện Hồn Tông tu luyện cấm pháp."],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c0940","tangDatToi":"đã nắm giữ để thác ấn","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c0940","loai":"xuất hiện","importance":"major","giaiDoan":"Đệ nhất cấm pháp Luyện Hồn Tông","text":"Vương Lâm thác ấn Cửu Chuyển Luyện Tiên quyết và lập thành đệ nhất cấm pháp của Luyện Hồn Tông.","anchor":"trở thành đệ nhất cấm pháp của Luyện Hồn Tông!"}]},"capNhatToi":"@c0940","nguon":["@c0940"]},{"id":"un-linh","name":"Uẩn Linh","cn":"","aliases":[],"loai":"cong-phap","loaiLabel":"Trung phẩm Tiên thuật","phamCap":"trung phẩm Tiên thuật","hePhai":"Lôi chi Tiên giới","soHuu":["Vương Lâm","Trần Đạo Tam Tử"],"blurb":"Uẩn Linh là trung phẩm Tiên thuật từng được Vương Lâm chọn từ Tàng Phẩm Các. Hắn dùng nó làm cái giá để Trần Đạo Tam Tử đồng ý tiến vào Yêu Linh chi địa.","detail":"Chương này nhắc lại Uẩn Linh như ví dụ về giá trị trao đổi rất lớn của Tiên thuật hoàn chỉnh trong Tàng Phẩm Các.","dinhDanh":"goc","nguonGoc":"Được Vương Lâm chọn từ Tàng Phẩm Các.","congNang":["Dùng làm cái giá trao đổi khiến Trần Đạo Tam Tử đồng ý tiến vào Yêu Linh chi địa."],"tabs":{"tienTrinh":[{"chuong":"@c0940","loai":"nhắc tới","importance":"normal","giaiDoan":"Cái giá trao đổi","text":"Uẩn Linh được nhắc là trung phẩm Tiên thuật Vương Lâm từng dùng để đổi lấy sự đồng ý của Trần Đạo Tam Tử.","anchor":"Trần Đạo Tam Tử gần như không chút nghĩ ngợi, không hề do dự đồng ý tiến vào Yêu Linh chi địa!"}]},"capNhatToi":"@c0940","nguon":["@c0940"]},{"id":"luyen-hon-thanh-tien","name":"Luyện Hồn Thành Tiên","cn":"","aliases":[],"loai":"cong-phap","loaiLabel":"Hạ phẩm Tiên thuật","phamCap":"hạ phẩm Tiên thuật đầy đủ","hePhai":"Luyện Hồn Tông","soHuu":["Vương Lâm","Âu Dương Hoa"],"blurb":"Luyện Hồn Thành Tiên là hạ phẩm Tiên thuật đầy đủ được Vương Lâm ban cho Âu Dương Hoa. Đây là phần thưởng dành cho mấy trăm năm Âu Dương Hoa duy trì Luyện Hồn Tông.","detail":"Trong lần xây dựng hệ thống truyền thừa cho Luyện Hồn Tông, Vương Lâm không keo kiệt với Âu Dương Hoa và trực tiếp xuất ra pháp môn đầy đủ này để ban thưởng.","dinhDanh":"goc","congNang":["Dùng làm pháp môn tu luyện hoàn chỉnh ban cho Âu Dương Hoa."],"nguoiTu":[{"ten":"Âu Dương Hoa","tuChuong":"@c0940","tangDatToi":"được truyền pháp","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c0940","loai":"xuất hiện","importance":"major","giaiDoan":"Ban thưởng cho Âu Dương Hoa","text":"Vương Lâm ban Luyện Hồn Thành Tiên cho Âu Dương Hoa làm phần thưởng cho mấy trăm năm duy trì Luyện Hồn Tông.","anchor":"coi như là phần thưởng cho mấy trăm năm qua của Âu Dương Hoa!"}]},"capNhatToi":"@c0940","nguon":["@c0940"]},{"id":"tien-phach-thuat","name":"Tiên Phách thuật","cn":"","aliases":[],"loai":"cong-phap","loaiLabel":"Trung phẩm Tiên thuật","phamCap":"trung phẩm Tiên thuật đầy đủ","hePhai":"Luyện Hồn Tông","soHuu":["Vương Lâm","Thập Tam"],"blurb":"Tiên Phách thuật là trung phẩm Tiên thuật đầy đủ gồm ba bước, được Vương Lâm chọn từ Tàng Phẩm Các. Hắn truyền pháp môn này cho Thập Tam sau khi xác lập quan hệ đại đệ tử.","detail":"Vương Lâm chọn Tiên Phách thuật trong Tàng Phẩm Các để Thập Tam từng bước tu luyện, đặt nền cho tuyến trưởng thành riêng của đại đệ tử Luyện Hồn Tông.","dinhDanh":"goc","dacDiem":"Gồm ba bước tu luyện.","congNang":["Giúp Thập Tam từng bước tu luyện sau khi thân thể được cải tạo."],"nguoiTu":[{"ten":"Thập Tam","tuChuong":"@c0940","tangDatToi":"được truyền pháp","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c0940","loai":"xuất hiện","importance":"major","giaiDoan":"Truyền cho Thập Tam","text":"Vương Lâm chọn Tiên Phách thuật từ Tàng Phẩm Các và truyền cho Thập Tam.","anchor":"Từ trong Tàng Phẩm Các, hắn lựa chọn một loại trung phẩm Tiên thuật đầy đủ tên là Tiên Phách thuật"}]},"capNhatToi":"@c0940","nguon":["@c0940"]},{"id":"cam-phap-luyen-hon-tong","name":"Cấm pháp Luyện Hồn Tông","cn":"","aliases":[],"loai":"cong-phap","loaiLabel":"Cấm pháp","phamCap":"dựa trên hạ phẩm Tiên thuật","hePhai":"Luyện Hồn Tông","soHuu":["Luyện Hồn Tông","Vương Lâm"],"blurb":"Cấm pháp Luyện Hồn Tông là hệ thống pháp môn do Vương Lâm phân giải từ Tiên thuật liên quan hồn phách. Nó được tạo ra để đệ tử Luyện Hồn Tông có thể tu luyện phù hợp với Hồn Phiên và hồn phách.","detail":"Vương Lâm chọn bốn loại hạ phẩm Tiên thuật liên quan hồn phách làm căn bản, rồi phân thành nhiều cấm pháp để truyền xuống thay vì để đệ tử trực tiếp học Tiên thuật.","dinhDanh":"goc","nguonGoc":"Do Vương Lâm lấy Tiên thuật làm căn bản rồi phân giải thành nhiều loại cấm pháp.","congNang":["Giúp đệ tử Luyện Hồn Tông tu luyện dựa trên hồn phách và Hồn Phiên."],"tabs":{"tienTrinh":[{"chuong":"@c0940","loai":"xuất hiện","importance":"normal","giaiDoan":"Truyền xuống tông môn","text":"Vương Lâm dùng Tiên thuật làm nền, phân ra nhiều cấm pháp để truyền cho Luyện Hồn Tông.","anchor":"Vương Lâm lấy Tiên thuật làm căn bản, phân ra nhiều loại cấm pháp rồi mới truyền xuống!"}]},"capNhatToi":"@c0940","nguon":["@c0940"]},{"id":"nguyen-than-thai-co-loi-long-dan-loi","name":"Nguyên thần Thái Cổ Lôi Long dẫn lôi","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Vương Lâm mượn nguyên thần Thái Cổ Lôi Long dẫn động lôi đình trên hơn phân nửa Yêu Linh chi địa để trấn áp dị lực xâm nhập nguyên thần.","detail":"Khi lực lượng như mực nước từ tượng đá màu đen tràn vào nguyên thần, nguyên thần Thái Cổ Lôi Long trong cơ thể Vương Lâm gầm rít, khiến lôi đình trên hơn phân nửa Yêu Linh chi địa biến động và hội tụ về thung lũng. Lôi đình nhập thể phối hợp với phòng hộ của Cổ Thần bì giáp, cuối cùng đánh tan điểm mực quỷ dị đang uy hiếp nguyên thần.","nguon":["@c0941"]},{"id":"co-than-bi-giap-phong-an","name":"Cổ Thần bì giáp phong ấn","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Cổ Thần bì giáp trên nguyên thần Vương Lâm phát thanh quang, phong bế đường lui của dị lực mực nước để lôi đình tiêu diệt.","detail":"Trong lúc dị lực từ tượng đá xâm nhập nguyên thần, Cổ Thần bì giáp hiện thanh quang và hình thành thế phong tỏa, khiến điểm mực không thể thoát. Nhờ sự phong bế này, lôi đình do Thái Cổ Lôi Long dẫn tới mới có thể tập trung đánh tan dị lực quỷ dị.","nguon":["@c0941"]},{"id":"te-luyen-phan-than-thu-hai","name":"Tế luyện phân thân thứ hai","cn":"","aliases":[],"loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Pháp môn Vương Lâm dùng để luyện tia Yêu Thức trong tượng đá thành phân thân thứ hai mang bản chất Cổ Yêu.","detail":"Sau khi xác nhận Cổ Yêu trong tượng là tia Yêu Thức Vân Yêu đã bị tín niệm Luyện Hồn bộ lạc cải biến thành hình tượng của mình, Vương Lâm dùng nguyên thần khí, thần thức và ấn ký để tế luyện nó. Quá trình này xác lập quan hệ chủ thứ, biến tia Yêu Thức thành phân thân thứ hai của hắn, nhưng phân thân còn phải ký thác vào tượng đá và cần yêu khí cúng bái để trưởng thành.","nguon":["@c0941"]},{"id":"lac-an-phan-boi","name":"Lạc ấn phản bội","cn":"","aliases":[],"loai":"khac","loaiLabel":"Cấm chế khống chế","phamCap":"","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Ấn ký khống chế Vương Lâm đặt lên phân thân thứ hai để ngăn khả năng phản chủ.","detail":"Trong quá trình tế luyện phân thân thứ hai, Vương Lâm khắc lạc ấn phản bội lên phân thân Cổ Yêu. Chỉ cần tâm niệm khẽ động, lạc ấn này có thể khiến phân thân khuất phục, là một tầng bảo đảm để phân thân không sinh hậu hoạn.","nguon":["@c0941"]},{"id":"thao-khong-thuat-doi-voi-khoi-loi-cua-tien-de-thanh-lam","name":"Thao Khống thuật đối với Khôi lỗi của Tiên Đế Thanh Lâm","cn":"","aliases":["Thao Khống thuật"],"loai":"bi-thuat","loaiLabel":"Khôi lỗi thuật","phamCap":"","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Thuật khống chế từng dùng với khôi lỗi của Tiên Đế Thanh Lâm, được Vương Lâm áp dụng thêm lên phân thân thứ hai.","detail":"Sau khi đặt lạc ấn phản bội, Vương Lâm tiếp tục thi triển Thao Khống thuật vốn dùng đối với khôi lỗi của Tiên Đế Thanh Lâm lên phân thân thứ hai. Nhờ chồng thêm tầng khống chế này, hắn mới yên tâm rằng phân thân Cổ Yêu đã bị khống chế hoàn toàn và không còn lưu lại hậu hoạn.","nguon":["@c0941"]},{"id":"cam-che-tien-phu-thu-tu","name":"Cấm chế Tiên phủ thứ tư","cn":"","loai":"khac","loaiLabel":"Trận pháp/cấm chế","phamCap":"không rõ","hePhai":"Tiên phủ","soHuu":[],"blurb":"Hệ thống cấm chế dày đặc trong Tiên phủ thứ tư, càng vào gần trung tâm uy lực càng mạnh.","detail":"Cấm chế trong Tiên phủ thứ tư không thể chỉ dựa tu vi cao thâm để cưỡng ép phá giải. Muốn bài trừ cần hiểu cơ cấu cấm chế, nếu không càng vào gần trung tâm càng dễ bị ngăn trở.","dinhDanh":"goc","congNang":["Phong tỏa đường tiến vào sâu trong Tiên phủ thứ tư và buộc người phá cấm phải hiểu cơ cấu cấm chế. @c0942"],"dacDiem":"Càng gần trung tâm Tiên phủ, uy lực cấm chế càng gần đỉnh và đòi hỏi tri thức cấm chế thay vì chỉ dựa sức mạnh.","capNhatToi":"@c0942","nguon":["@c0942"]},{"id":"cam-che-cau-da-ranh-gioi-noi-phu","name":"Cấm chế cầu đá ranh giới Nội phủ","cn":"","loai":"khac","loaiLabel":"Trận pháp/cấm chế","phamCap":"không rõ","hePhai":"Tiên phủ","soHuu":[],"blurb":"Cấm chế tại con sông và cầu đá ngăn đường vào Nội phủ của Tiên phủ thứ tư.","detail":"Cấm chế này khiến nhóm Tư Đồ Nam bị cản năm canh giờ, Phù Phong Tử không tìm ra manh mối và lo cưỡng ép phá giải sẽ dẫn tới biến cố khó lường. Vương Lâm nhận thấy nơi đây khác cấm chế bên ngoài, có sát khí và có thể là đạo kiểm soát đầu tiên vào trong Tiên phủ.","dinhDanh":"goc","congNang":["Phong tỏa cầu đá và con sông nhỏ dẫn vào Nội phủ. @c0942","Có thể gây phản ứng dây chuyền hoặc biến cố khó lường nếu bị cưỡng ép bài trừ. @c0942"],"dacDiem":"Ẩn sát khí trong khoảng trăm bước trước cầu đá, khác hẳn các cấm chế bên ngoài Tiên phủ.","capNhatToi":"@c0942","nguon":["@c0942"]},{"id":"thu-an-cam-che-pha-tran-bao","name":"Thủ ấn cấm chế phá trần bạo","cn":"","loai":"khac","loaiLabel":"Cấm chế ứng dụng","phamCap":"không rõ","hePhai":"Cấm chế","soHuu":["Vương Lâm"],"blurb":"Ứng dụng cấm chế được Vương Lâm dùng để phá điểm sụp trong trần bạo đen của Tiên phủ.","detail":"Vương Lâm bấm quyết tạo một đạo cấm chế có thời gian, phương vị, địa điểm và uy lực được tính chính xác, khiến trần bạo đen trước mặt sụp xuống vừa đủ để hắn xuyên qua. Chỉ cần sai lệch nhỏ, người vượt qua sẽ bị trần bạo nghiền nát.","congNang":["Tạo điểm sụp trong trần bạo cấm chế để mở đường vượt qua khu vực nguy hiểm @c0943"],"nguon":["@c0943"]},{"id":"cam-che-kien-vi-ben-trai","name":"Cấm chế kiền vị bên trái","cn":"","loai":"khac","loaiLabel":"Điểm phá cấm","phamCap":"không rõ","hePhai":"Cấm chế","soHuu":["Vương Lâm"],"blurb":"Điểm phá trong biến hóa đầu tiên của cấm chế trăm bước trước cầu đá.","detail":"Vương Lâm tính ra kiền vị bên trái là chỗ có thể kích phá biến hóa sương mù và sóng gợn. Hắn sai Ngân Y Luyện Thi công kích vị trí này, khiến phạm vi trăm trượng như bị cuồng phong quét qua rồi bình ổn trở lại.","congNang":["Phá biến hóa sương mù và sóng gợn đầu tiên của phạm vi cấm chế trăm bước @c0943"],"nguon":["@c0943"]},{"id":"vu-hau-doc-huong","name":"Vũ hậu độc hương","cn":"","aliases":[],"loai":"khac","loaiLabel":"Kỳ độc","phamCap":"xếp thứ chín mươi ba @c0944","hePhai":"Vũ chi Tiên giới","soHuu":[],"blurb":"Kỳ độc do nhiều loại hoa phối hợp tự nhiên tạo thành trong hoa viên Tiên phủ. Người ngửi phải có thể tu vi không thuận, hít sâu còn có nguy cơ phế bỏ tu vi.","detail":"Phù Phong Tử nhận ra Vũ hậu độc hương nhờ điển tịch Tiên giới về độc công Vũ chi Tiên giới. Độc hương này không bị gió thường thổi tan, buộc Vương Lâm phải gọi ngân thi đối phó.","dinhDanh":"goc","thuocTinh":"độc hương hoa cỏ","nguonGoc":"độc công Vũ chi Tiên giới được điển tịch ghi lại @c0944","congNang":["Khiến người ngửi phải tu vi không thuận, hít sâu có thể phế bỏ tu vi @c0944"],"uyLuc":"Độc hương lan khắp hoa viên và không bị gió thường thổi tan.","dacDiem":"Sinh ra từ sự phối hợp tự nhiên của nhiều loại hoa.","trangThai":"xuất hiện trong hoa viên Tiên phủ @c0944","capNhatToi":"@c0944","tabs":{"tienTrinh":[]},"nguon":["@c0944"]},{"id":"hoa-linh","name":"Hoa Linh","cn":"","aliases":[],"loai":"khac","loaiLabel":"Độc vật","phamCap":"xếp thứ bốn mươi chín @c0944","hePhai":"Vũ chi Tiên giới","soHuu":[],"blurb":"Độc vật trong hoa viên Tiên phủ, cao hơn Vũ hậu độc hương rất nhiều. Chúng hiện thành hư ảnh thiếu nữ, dưới mỗi đóa hoa lại có hài cốt nhỏ bé.","detail":"Hoa Linh được Phù Phong Tử giải thích là một loại độc do phối hợp tự nhiên mà thành nhưng gắn với cách luyện Hoa Tiên tàn khốc. Trong chương, Hoa Linh vây quanh ngân thi, bộc phát oán khí muốn đồng hóa nàng rồi bị sương trắng làm tan biến.","dinhDanh":"goc","thuocTinh":"độc vật hoa linh có oán khí","nguonGoc":"liên quan phương pháp luyện Hoa Tiên bằng nữ đồng trinh bị mai táng @c0944","congNang":["Mang oán khí vây quanh mục tiêu và muốn đồng hóa đối phương @c0944"],"uyLuc":"Có thể hình thành từ cả hoa viên và gây áp lực lên ngân thi độc thi.","dacDiem":"Hiện ra dưới dạng các thiếu nữ hư ảo từ hoa cỏ.","trangThai":"bị sương trắng của ngân thi làm tan trong hoa viên @c0944","capNhatToi":"@c0944","tabs":{"tienTrinh":[{"chuong":"@c0944","loai":"xuất hiện","importance":"major","giaiDoan":"hiện hình trong hoa viên","text":"Hoa Linh hiện thành các thiếu nữ hư ảo, để lộ hài cốt dưới hoa và biến hoa viên thành một mảnh nghĩa địa. Chúng vây quanh ngân thi rồi bị sương trắng làm tan biến.","anchor":"Đưa mắt nhìn đi, rõ ràng phiến hoa cỏ này chính là một mảnh nghĩa địa"}]},"nguon":["@c0944"]},{"id":"hoa-tien","name":"Hoa Tiên","cn":"","aliases":[],"loai":"khac","loaiLabel":"Độc vật có linh tính","phamCap":"xếp thứ mười @c0944","hePhai":"Vũ chi Tiên giới","soHuu":[],"blurb":"Hoa Tiên không phải Tiên nhân mà là một loại độc có linh tính, có thể biến ảo hình người. Theo Phù Phong Tử, nó sinh từ phương pháp luyện dược nhân và mai táng nữ đồng trinh cực kỳ tàn khốc.","detail":"Phù Phong Tử giải thích nữ đồng trinh trong nhân gian bị cho dùng dược vật nhiều năm để biến thành dược nhân, sau đó bị mai táng tập thể để linh hồn dung hợp. Nếu một linh hồn cắn nuốt toàn bộ linh hồn còn lại thì có cơ hội hóa thành Hoa Tiên, loại độc xếp thứ mười.","dinhDanh":"goc","thuocTinh":"độc có linh tính","nguonGoc":"do nữ đồng trinh bị luyện thành dược nhân rồi mai táng tập thể, linh hồn dung hợp mà có tỷ lệ hóa thành @c0944","congNang":["Có linh tính và có thể biến ảo hình người @c0944"],"uyLuc":"Được xếp cao hơn Hoa Linh rất nhiều trong các kỳ độc được Phù Phong Tử nhắc tới.","dacDiem":"Không phải Tiên nhân mà là độc vật đặc thù.","trangThai":"được nhắc qua lai lịch trong Tiên phủ @c0944","capNhatToi":"@c0944","tabs":{"tienTrinh":[{"chuong":"@c0944","loai":"nhắc tới","importance":"major","giaiDoan":"hé lộ lai lịch","text":"Phù Phong Tử nói Hoa Tiên là độc vật có linh tính xếp thứ mười, sinh từ phương pháp luyện dược nhân và mai táng nữ đồng trinh trong nhân gian.","anchor":"Hoa Tiên cũng không phải Tiên nhân, đồng dạng cũng là một loại độc"}]},"nguon":["@c0944"]},{"id":"doc-thi-cua-ngan-thi","name":"Độc thi của ngân thi","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Năng lực thân thể","phamCap":"phối hợp tu vi Tịnh Niết sơ kỳ @c0944","hePhai":"Ngân Y Luyện Thi","soHuu":["Ngân Y Luyện Thi"],"blurb":"Năng lực độc tố dung hợp trong thi thể ngân thi, được Vương Lâm xem là sức mạnh chân chính của nàng. Nhờ bản chất độc thi, nàng có thể hút độc hương và phá Hoa Linh.","detail":"Sau khi tế luyện ngân thi, Vương Lâm nhận ra thần thông và pháp bảo của nàng không phải điểm đáng sợ nhất. Điều lợi hại thật sự là các loại độc tố dung hợp trong thi thể, phối hợp với tu vi Tịnh Niết sơ kỳ.","dinhDanh":"goc","thuocTinh":"độc tố thi thể","nguonGoc":"hình thành từ nhiều độc tố dung hợp trong thi thể ngân thi @c0944","congNang":["Hút Vũ hậu độc hương và dùng độc vụ phá Hoa Linh @c0944"],"uyLuc":"Khiến ngân thi trở thành tồn tại khó trêu chọc trong Tiên phủ.","dacDiem":"Sức mạnh nằm ở độc tố hơn là thần thông hay pháp bảo.","trangThai":"đang được ngân thi vận dụng @c0944","capNhatToi":"@c0944","tabs":{"tienTrinh":[{"chuong":"@c0944","loai":"hé lộ tầng-chiêu","importance":"major","giaiDoan":"bộc lộ bản chất độc thi","text":"Chương xác nhận sức mạnh chân chính của ngân thi là độc tố dung hợp trong thi thể, không phải thần thông hay pháp bảo thông thường.","anchor":"Chỗ lợi hại chân chính của nàng đó chính là độc"}]},"nguon":["@c0944"]},{"id":"quy-xac-phong-ho","name":"Quy xác phòng hộ","cn":"","aliases":["phòng hộ mai rùa"],"loai":"khac","loaiLabel":"Trận pháp phòng hộ","phamCap":"Không rõ","hePhai":"Tiên phủ","soHuu":["Tiên phủ"],"blurb":"Cơ chế phòng hộ do lầu các quanh đại điện biến ảo và ánh sáng hợp thành hư ảnh mai rùa. Lớp phòng hộ này chịu được Cổ Thần Tí cùng nhiều đợt liên thủ mà vẫn không sụp.","detail":"Khi Vương Lâm tiến gần đại điện, các lầu các xung quanh biến ảo phương vị, cường quang dung hợp thành hư ảnh mai rùa bao phủ đại điện. Quy xác phòng hộ cực kỳ kiên cố, chỉ ảm đạm một phần sau khi chịu công kích của Vương Lâm, Phù Phong Tử và các tu sĩ khác.","dinhDanh":"goc","thuocTinh":"Phòng hộ","uyLuc":"Chịu được Cổ Thần Tí và nhiều thần thông liên thủ mà vẫn bảo vệ đại điện.","dacDiem":"Hình thành từ biến hóa phương vị của lầu các và cường quang quanh đại điện.","congNang":["Bao phủ và bảo vệ đại điện Tiên phủ bằng hư ảnh mai rùa @c0945","Chống chịu công kích mạnh của nhiều tu sĩ và thần thông @c0945"],"trangThai":"đang kích hoạt","capNhatToi":"@c0945","tabs":{"tienTrinh":[{"chuong":"@c0945","loai":"xuất hiện","importance":"normal","giaiDoan":"Kích hoạt quanh đại điện","text":"Quy xác phòng hộ hiện ra quanh đại điện, chặn đường tiến của Vương Lâm và nhóm tu sĩ.","anchor":"Cường quang này dung hợp lại, không ngờ phảng phất như hư ảnh của một chiếc mai rùa"}]},"nguon":["@c0945"]},{"id":"tien-thuat-hoa-thu-cua-bon-lao-gia-ao-xanh","name":"Tiên thuật hóa thú của bốn lão già áo xanh","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Tiên phủ","soHuu":["Bốn lão già áo xanh hồn thể"],"blurb":"Tiên thuật hợp kích của bốn hồn thể áo xanh thủ hộ quy xác. Thuật mượn tiên khí trong Tiên phủ hóa thành cự viên, hắc mãng, đại điêu và tiên sơn để vây sát Vương Lâm.","detail":"Bốn lão già áo xanh đồng thời ra tay, mỗi người hóa một dạng công kích khác nhau gồm cự viên, hắc mãng, đại điêu và hư ảnh tiên sơn. Đòn liên kích này tạo thế tuyệt sát nhiều hướng nhưng bị Vương Lâm lần lượt phá giải.","dinhDanh":"goc","thuocTinh":"Tiên khí, hóa hình","uyLuc":"Tạo hợp kích nhiều hướng bên trong Tiên phủ.","dacDiem":"Bốn hồn thể phối hợp, mỗi người hóa ra một hình thái công kích riêng.","congNang":["Hóa cự viên, hắc mãng, đại điêu và tiên sơn để hợp kích mục tiêu @c0945"],"trangThai":"bị phá","capNhatToi":"@c0945","nguoiTu":[{"ten":"Bốn lão già áo xanh hồn thể","tuChuong":"@c0945","tangDatToi":"Không rõ","trangThai":"đã thi triển"}],"tabs":{"tienTrinh":[{"chuong":"@c0945","loai":"thi triển","importance":"normal","giaiDoan":"Hợp kích Vương Lâm","text":"Bốn lão già áo xanh thi triển Tiên thuật hóa thú và tiên sơn để cùng công kích Vương Lâm.","anchor":"Trong khoảng thời gian ngắn, bốn lão già này đồng thời ra tay"}]},"nguon":["@c0945"]},{"id":"tu-mau-dao-kho","name":"Tử mẫu đạo khô","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Vương Lâm","soHuu":["Vương Lâm"],"blurb":"Thần thông từ mu bàn tay phải Vương Lâm thoát ly, hóa thành đầu lâu mãnh thú âm trầm. Trong trận với bốn lão già áo xanh, nó phát u quang khiến đại điêu do Tiên thuật hóa thành thạch điêu.","detail":"Tử mẫu đạo khô xuất hiện khi đại điêu lao tới Vương Lâm. Đầu lâu mãnh thú do nó hóa ra gầm thét, phát u quang bao phủ đại điêu và khiến đối phương hóa đá trước khi tan vỡ.","dinhDanh":"goc","thuocTinh":"Âm trầm, hóa đá","uyLuc":"Có thể khiến đại điêu do Tiên thuật biến thành thạch điêu.","dacDiem":"Thoát ra từ mu bàn tay phải của Vương Lâm và hóa đầu lâu mãnh thú.","congNang":["Phát u quang khiến mục tiêu do Tiên thuật hóa ra bị hóa đá @c0945"],"trangThai":"Vương Lâm đang dùng","capNhatToi":"@c0945","nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c0945","tangDatToi":"Không rõ","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c0945","loai":"thi triển","importance":"normal","giaiDoan":"Hóa đá đại điêu","text":"Tử mẫu đạo khô hóa đầu lâu mãnh thú và phát u quang khiến đại điêu hóa đá.","anchor":"Thần sắc của Vương Lâm như thường, há mồm phun ra một thứ"}]},"nguon":["@c0945"]},{"id":"diet-than-mau","name":"Diệt Thần Mâu","cn":"","loai":"than-thong","loaiLabel":"Thần thông / Cổ Thần chiến kỹ","phamCap":"không rõ","hePhai":"Cổ Thần","soHuu":["Vương Lâm"],"blurb":"Diệt Thần Mâu được Vương Lâm triệu ra trong Tiên phủ để phá mai rùa trước thông đạo đại điện.","detail":"Vương Lâm gọi hư ảnh trường thương đen từ hư không, phối hợp hư ảnh Cổ Thần phía sau và Cổ Thần lực Ngũ tinh vương tộc để công phá mai rùa. Sau khi mai rùa sụp đổ, Diệt Thần Mâu tiếp tục lao về đại điện nhưng bị Hoa Tiên dùng hoa tím hồng ngăn lại.","dinhDanh":"goc","congNang":["Công phá lớp mai rùa phong bế thông đạo Tiên phủ khi phối hợp Cổ Thần lực Ngũ tinh vương tộc @c0946"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c0946","tangDatToi":"thi triển phá giáp","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c0946","loai":"thi triển","importance":"normal","giaiDoan":"Phá mai rùa trong Tiên phủ","text":"Vương Lâm triệu Diệt Thần Mâu, phối hợp hư ảnh Cổ Thần và Cổ Thần lực để đánh sụp mai rùa trước thông đạo, sau đó bị Hoa Tiên dùng hoa tím hồng chặn lại.","anchor":"Phía sau Vương Lâm lúc này xuất hiện một hư ảnh Cổ Thần."}]},"capNhatToi":"@c0946","nguon":["@c0946"]},{"id":"co-than-luc-ngu-tinh-vuong-toc","name":"Cổ Thần lực Ngũ tinh vương tộc","cn":"","loai":"than-thong","loaiLabel":"Cổ Thần lực","phamCap":"Ngũ tinh vương tộc","hePhai":"Vương tộc Cổ Thần","soHuu":["Vương Lâm"],"blurb":"Cổ Thần lực Ngũ tinh vương tộc là lực lượng được Vương Lâm vận dụng khi phá mai rùa trong Tiên phủ.","detail":"Con mắt thứ ba của Vương Lâm hiện ra, Ngũ tinh vương tộc xoay tròn và truyền Cổ Thần lực dung nhập toàn thân. Lực này làm nền cho đòn Diệt Thần Mâu và tạo dị tượng đất đá, nước, bụi bay lên trong động phủ.","dinhDanh":"goc","thuocTinh":"Cổ Thần lực","congNang":["Truyền lực vào toàn thân Vương Lâm để gia trì Diệt Thần Mâu phá giáp @c0946"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c0946","tangDatToi":"Ngũ tinh vương tộc","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c0946","loai":"thi triển","importance":"normal","giaiDoan":"Gia trì Diệt Thần Mâu","text":"Vương Lâm vận Cổ Thần lực Ngũ tinh vương tộc, khiến hư ảnh Cổ Thần hiện phía sau và lực lượng dung nhập toàn thân trước khi phá mai rùa.","anchor":"Phía sau Vương Lâm lúc này xuất hiện một hư ảnh Cổ Thần."}]},"capNhatToi":"@c0946","nguon":["@c0946"]},{"id":"hoa-tim-hong-cua-hoa-tien","name":"Hoa tím hồng của Hoa Tiên","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"không rõ","hePhai":"Hoa Tiên","soHuu":["Nữ tử áo trắng"],"blurb":"Hoa tím hồng của Hoa Tiên là thần thông ngăn Diệt Thần Mâu và phá Lôi chi Tiên giới Toái phiến.","detail":"Nữ tử áo trắng điểm tay khiến vô số đóa hoa tím hồng xuất hiện, ngăn Diệt Thần Mâu sau khi mai rùa vỡ. Những đóa hoa này tiếp tục va chạm với Lôi chi Tiên giới Toái phiến và khiến pháp bảo hộ mệnh tứ phân ngũ liệt.","dinhDanh":"goc","congNang":["Ngăn Diệt Thần Mâu đang lao vào đại điện @c0946","Va chạm phá vỡ Lôi chi Tiên giới Toái phiến của Vương Lâm @c0946"],"nguoiTu":[{"ten":"Nữ tử áo trắng","tuChuong":"@c0946","tangDatToi":"thi triển","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c0946","loai":"thi triển","importance":"normal","giaiDoan":"Chặn mâu phá Toái phiến","text":"Hoa Tiên triệu vô số hoa tím hồng để ngăn Diệt Thần Mâu, rồi khiến các đóa hoa va chạm đánh vỡ Lôi chi Tiên giới Toái phiến.","anchor":"Theo thanh âm này xuất hiện, những đóa hoa kia liền va chạm với Tiên giới Toái phiến, tạo ra một tiếng ầm lớn."}]},"capNhatToi":"@c0946","nguon":["@c0946"]},{"id":"hoa-khoi-thanh-hoa","name":"Hóa khói thành hoa","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"không rõ","hePhai":"Hoa Tiên","soHuu":["Nữ tử áo trắng"],"blurb":"Hóa khói thành hoa là thủ đoạn Hoa Tiên dùng để chế ngự khói nhiều màu của ngân thi.","detail":"Nữ tử áo trắng dùng một chỉ khiến làn khói nhiều màu do ngân thi phun ra hóa thành một đóa hoa nhiều màu, lơ lửng bất động trong không trung.","dinhDanh":"goc","congNang":["Biến khói nhiều màu của ngân thi thành đóa hoa nhiều màu bất động @c0946"],"nguoiTu":[{"ten":"Nữ tử áo trắng","tuChuong":"@c0946","tangDatToi":"thi triển","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c0946","loai":"thi triển","importance":"normal","giaiDoan":"Chế ngự khói ngân thi","text":"Hoa Tiên điểm một chỉ khiến khói nhiều màu của ngân thi hóa thành một đóa hoa nhiều màu và mất tác dụng tiếp tục công phá.","anchor":"Một bàn tay trắng nõn từ chỗ tối trong đại điện vươn ra, nhẹ nhàng điểm về phía Diệt Thần Mâu một cái."}]},"capNhatToi":"@c0946","nguon":["@c0946"]},{"id":"tang-hoa","name":"Táng hoa","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"không rõ","hePhai":"","soHuu":["Nữ tử áo trắng"],"blurb":"Thần thông hoa hệ do nữ tử áo trắng thi triển trong động phủ, biến không gian giao chiến thành biển hoa héo rũ chôn vùi đối thủ.","detail":"Khi nữ tử áo trắng kết ấn thi triển, vô số đóa hoa trong động phủ nở đến cực hạn rồi nhanh chóng héo rũ, cánh hoa như mưa tụ lại bao phủ Vương Lâm, tạo thế chôn vùi trong rừng hoa.","congNang":["Khiến hoa trong phạm vi động phủ nở rộ rồi héo rũ, cánh hoa hội tụ để bao phủ và chôn vùi mục tiêu @c0947"],"nguoiTu":[{"ten":"Nữ tử áo trắng","tuChuong":"@c0947","tangDatToi":"","trangThai":"thi triển"}],"tabs":{"tienTrinh":[]},"capNhatToi":"@c0947","nguon":["@c0947"]},{"id":"hoan-vu","name":"Hoán vũ","cn":"","loai":"than-thong","loaiLabel":"Tiên thuật","phamCap":"không rõ","hePhai":"Bạch Phàm","soHuu":["Vương Lâm"],"blurb":"Một trong ba Tiên thuật của Bạch Phàm được Vương Lâm dùng phối hợp với Hô phong và Tản đậu thành binh.","detail":"Trong nguy cơ trước Táng hoa, Vương Lâm thi triển Hoán vũ nối tiếp Hô phong, dẫn mưa và tiên khí dung nhập, khiến mưa hóa thành băng tuyết phối hợp với hắc phong phá rừng hoa.","congNang":["Dẫn mưa và tiên khí, hóa thành băng tuyết phối hợp với hắc phong trong tổ hợp ba Tiên thuật @c0947"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c0947","tangDatToi":"","trangThai":"thi triển"}],"tabs":{"tienTrinh":[]},"capNhatToi":"@c0947","nguon":["@c0947"]},{"id":"tan-dau-thanh-binh","name":"Tản đậu thành binh","cn":"","loai":"than-thong","loaiLabel":"Tiên thuật","phamCap":"không rõ","hePhai":"Bạch Phàm","soHuu":["Vương Lâm"],"blurb":"Tiên thuật của Bạch Phàm được Vương Lâm phối hợp Phong Tiên Ấn để gọi ra vô số chiến hồn.","detail":"Vương Lâm dùng Tản đậu thành binh cùng Phong Tiên Ấn, thả ra vô số chiến hồn, trong đó có Huyết Tổ, hợp cùng Hô phong và Hoán vũ tạo phong bạo phá rừng hoa.","congNang":["Triệu xuất vô số chiến hồn từ Phong Tiên Ấn để hợp lực công kích @c0947"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c0947","tangDatToi":"","trangThai":"thi triển"}],"tabs":{"tienTrinh":[]},"capNhatToi":"@c0947","nguon":["@c0947"]},{"id":"bon-nguyen-luc","name":"Bổn nguyên lực","cn":"","loai":"khac","loaiLabel":"Lực lượng","phamCap":"không rõ","hePhai":"","soHuu":["Nữ tử áo trắng","Vương Lâm"],"blurb":"Lực lượng cấp bổn nguyên xuất hiện trong quang đoàn của nữ tử áo trắng và trong con mắt thứ ba của Vương Lâm.","detail":"Quang đoàn của nữ tử áo trắng chứa một tia bổn nguyên lực, đủ khiến ba đại thần thông của Vương Lâm thoái hóa rồi tan rã. Vương Lâm dùng bổn nguyên lực trong con mắt thứ ba để triệt tiêu quang đoàn thứ hai, nhưng phần lực lượng dự trữ trong mắt cũng tiêu hao nhanh.","congNang":["Làm tổ hợp ba đại thần thông thoái hóa, phân rã và tan biến @c0947","Có thể được bổn nguyên lực trong con mắt thứ ba của Vương Lâm dùng để triệt tiêu lẫn nhau @c0947"],"nguoiTu":[{"ten":"Nữ tử áo trắng","tuChuong":"@c0947","tangDatToi":"","trangThai":"thi triển"},{"ten":"Vương Lâm","tuChuong":"@c0947","tangDatToi":"","trangThai":"thi triển"}],"tabs":{"tienTrinh":[]},"capNhatToi":"@c0947","nguon":["@c0947"]}]};
